-- 2026-03-05_receiving_qa_and_zoho_fields.sql
-- ============================================================
-- Receiving + QA + Zoho alignment
-- Adds required enums, receiving columns, receiving_lines table, and repair_service.repaired_by.

DO $$
BEGIN
  CREATE TYPE qa_status_enum AS ENUM (
    'PENDING',
    'PASSED',
    'FAILED_DAMAGED',
    'FAILED_INCOMPLETE',
    'FAILED_FUNCTIONAL',
    'HOLD'
  );
EXCEPTION
  WHEN duplicate_object THEN NULL;
END $$;

DO $$
BEGIN
  CREATE TYPE disposition_enum AS ENUM ('ACCEPT', 'HOLD', 'RTV', 'SCRAP', 'REWORK');
EXCEPTION
  WHEN duplicate_object THEN NULL;
END $$;

DO $$
BEGIN
  CREATE TYPE condition_grade_enum AS ENUM ('BRAND_NEW', 'USED_A', 'USED_B', 'USED_C', 'PARTS');
EXCEPTION
  WHEN duplicate_object THEN NULL;
END $$;

DO $$
BEGIN
  CREATE TYPE return_platform_enum AS ENUM ('AMZ', 'EBAY_DRAGONH', 'EBAY_USAV', 'EBAY_MK', 'FBA', 'WALMART', 'ECWID');
EXCEPTION
  WHEN duplicate_object THEN NULL;
END $$;

DO $$
BEGIN
  CREATE TYPE target_channel_enum AS ENUM ('ORDERS', 'FBA');
EXCEPTION
  WHEN duplicate_object THEN NULL;
END $$;

ALTER TABLE receiving
  ADD COLUMN IF NOT EXISTS receiving_date_time TIMESTAMP,
  ADD COLUMN IF NOT EXISTS received_at TIMESTAMP,
  ADD COLUMN IF NOT EXISTS received_by INTEGER REFERENCES staff(id),
  ADD COLUMN IF NOT EXISTS unboxed_at TIMESTAMP,
  ADD COLUMN IF NOT EXISTS unboxed_by INTEGER REFERENCES staff(id),
  ADD COLUMN IF NOT EXISTS qa_status qa_status_enum NOT NULL DEFAULT 'PENDING',
  ADD COLUMN IF NOT EXISTS disposition_code disposition_enum NOT NULL DEFAULT 'HOLD',
  ADD COLUMN IF NOT EXISTS condition_grade condition_grade_enum NOT NULL DEFAULT 'BRAND_NEW',
  ADD COLUMN IF NOT EXISTS is_return BOOLEAN NOT NULL DEFAULT FALSE,
  ADD COLUMN IF NOT EXISTS return_platform return_platform_enum,
  ADD COLUMN IF NOT EXISTS return_reason TEXT,
  ADD COLUMN IF NOT EXISTS needs_test BOOLEAN NOT NULL DEFAULT FALSE,
  ADD COLUMN IF NOT EXISTS assigned_tech_id INTEGER REFERENCES staff(id),
  ADD COLUMN IF NOT EXISTS target_channel target_channel_enum,
  ADD COLUMN IF NOT EXISTS zoho_purchase_receive_id TEXT,
  ADD COLUMN IF NOT EXISTS zoho_warehouse_id TEXT,
  ADD COLUMN IF NOT EXISTS created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  ADD COLUMN IF NOT EXISTS updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW();

-- Keep legacy rows valid by backfilling receiving_date_time from date_time when present.
DO $$
BEGIN
  IF EXISTS (
    SELECT 1
    FROM information_schema.columns
    WHERE table_name = 'receiving'
      AND column_name = 'date_time'
  ) THEN
    EXECUTE $sql$
      UPDATE receiving
      SET receiving_date_time = COALESCE(
        receiving_date_time,
        NULLIF(date_time, '')::timestamp
      )
      WHERE receiving_date_time IS NULL
        AND date_time IS NOT NULL
        AND date_time <> ''
    $sql$;
  END IF;
END $$;

ALTER TABLE receiving
  ALTER COLUMN receiving_date_time SET DEFAULT NOW();

UPDATE receiving
SET receiving_date_time = NOW()
WHERE receiving_date_time IS NULL;

ALTER TABLE receiving
  ALTER COLUMN receiving_date_time SET NOT NULL;

CREATE TABLE IF NOT EXISTS receiving_lines (
  id SERIAL PRIMARY KEY,
  receiving_id INTEGER NOT NULL REFERENCES receiving(id) ON DELETE CASCADE,
  zoho_item_id TEXT NOT NULL,
  quantity INTEGER NOT NULL,
  qa_status qa_status_enum NOT NULL DEFAULT 'PENDING',
  disposition_code disposition_enum NOT NULL DEFAULT 'HOLD',
  condition_grade condition_grade_enum NOT NULL DEFAULT 'BRAND_NEW',
  disposition_audit JSONB NOT NULL DEFAULT '[]'::jsonb
);

CREATE INDEX IF NOT EXISTS idx_receiving_lines_receiving_id ON receiving_lines(receiving_id);
CREATE INDEX IF NOT EXISTS idx_receiving_zoho_purchase_receive_id ON receiving(zoho_purchase_receive_id);
CREATE INDEX IF NOT EXISTS idx_receiving_qa_status ON receiving(qa_status);
CREATE INDEX IF NOT EXISTS idx_receiving_is_return ON receiving(is_return);

ALTER TABLE repair_service
  ADD COLUMN IF NOT EXISTS repaired_by INTEGER REFERENCES staff(id);

-- ============================================================
-- 2026-03-05_work_assignments_entity_join_integrity.sql
-- ============================================================
-- Migration: Strengthen work_assignments ↔ orders/receiving join reliability
--   1. Remove duplicate active-unique index
--   2. Add partial indexes for ORDER and RECEIVING entity lookups
--   3. Add packer assignment queue index (mirrors tech index)
--   4. Add composite index on orders.id + is_shipped for fast lateral joins
--   5. Cascade-delete trigger: deleting an order/receiving row auto-cancels
--      its work_assignments (no dangling entity_id references)
--   6. Purge any orphaned work_assignments already in the DB
-- Date: 2026-03-05

BEGIN;

-- ─────────────────────────────────────────────────────────────────────────────
-- 1. Remove duplicate active-unique index (keep ux_work_assignments_active_entity)
-- ─────────────────────────────────────────────────────────────────────────────
DROP INDEX IF EXISTS idx_work_assignments_active_unique;

-- ─────────────────────────────────────────────────────────────────────────────
-- 2. Partial indexes for ORDER and RECEIVING lateral join patterns
--    Pattern used by every query:
--      WHERE entity_type = 'ORDER' AND entity_id = o.id
--        AND work_type = 'TEST' AND status IN ('ASSIGNED','IN_PROGRESS')
-- ─────────────────────────────────────────────────────────────────────────────

-- Fast lookup of active ORDER assignments
CREATE INDEX IF NOT EXISTS idx_wa_order_entity_active
  ON work_assignments (entity_id, work_type, status)
  WHERE entity_type = 'ORDER'
    AND status IN ('ASSIGNED', 'IN_PROGRESS');

-- Fast lookup of active RECEIVING assignments
CREATE INDEX IF NOT EXISTS idx_wa_receiving_entity_active
  ON work_assignments (entity_id, work_type, status)
  WHERE entity_type = 'RECEIVING'
    AND status IN ('ASSIGNED', 'IN_PROGRESS');

-- ─────────────────────────────────────────────────────────────────────────────
-- 3. Packer assignment queue index (mirrors idx_work_assignments_assignee_status)
-- ─────────────────────────────────────────────────────────────────────────────
CREATE INDEX IF NOT EXISTS idx_wa_packer_queue
  ON work_assignments (assigned_packer_id, status, work_type, priority, assigned_at)
  WHERE assigned_packer_id IS NOT NULL;

-- ─────────────────────────────────────────────────────────────────────────────
-- 4. Composite index on orders.id + is_shipped – used by JOIN + WHERE together
-- ─────────────────────────────────────────────────────────────────────────────
CREATE INDEX IF NOT EXISTS idx_orders_id_is_shipped
  ON orders (id, is_shipped);

-- ─────────────────────────────────────────────────────────────────────────────
-- 5. Trigger functions: cascade-delete work_assignments on orders/receiving delete
--    Uses CANCEL rather than hard-delete so audit history is preserved.
-- ─────────────────────────────────────────────────────────────────────────────

-- Trigger function shared by both tables
CREATE OR REPLACE FUNCTION fn_cancel_work_assignments_on_entity_delete()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  UPDATE work_assignments
  SET
    status     = 'CANCELED',
    updated_at = NOW()
  WHERE entity_type = TG_ARGV[0]::work_entity_type_enum
    AND entity_id   = OLD.id
    AND status IN ('ASSIGNED', 'IN_PROGRESS');
  RETURN OLD;
END;
$$;

-- Trigger on orders
DROP TRIGGER IF EXISTS trg_cancel_wa_on_order_delete ON orders;
CREATE TRIGGER trg_cancel_wa_on_order_delete
  BEFORE DELETE ON orders
  FOR EACH ROW
  EXECUTE FUNCTION fn_cancel_work_assignments_on_entity_delete('ORDER');

-- Trigger on receiving
DROP TRIGGER IF EXISTS trg_cancel_wa_on_receiving_delete ON receiving;
CREATE TRIGGER trg_cancel_wa_on_receiving_delete
  BEFORE DELETE ON receiving
  FOR EACH ROW
  EXECUTE FUNCTION fn_cancel_work_assignments_on_entity_delete('RECEIVING');

-- ─────────────────────────────────────────────────────────────────────────────
-- 6. Purge orphaned work_assignments already in the DB
--    (entity_id references a row that no longer exists)
-- ─────────────────────────────────────────────────────────────────────────────

-- Cancel orphaned ORDER assignments
UPDATE work_assignments
SET status = 'CANCELED', updated_at = NOW()
WHERE entity_type = 'ORDER'
  AND status IN ('ASSIGNED', 'IN_PROGRESS')
  AND NOT EXISTS (
    SELECT 1 FROM orders WHERE orders.id = work_assignments.entity_id
  );

-- Cancel orphaned RECEIVING assignments
UPDATE work_assignments
SET status = 'CANCELED', updated_at = NOW()
WHERE entity_type = 'RECEIVING'
  AND status IN ('ASSIGNED', 'IN_PROGRESS')
  AND NOT EXISTS (
    SELECT 1 FROM receiving WHERE receiving.id = work_assignments.entity_id
  );

COMMIT;

-- ============================================================
-- 2026-03-05_work_assignments_split_assignee_remove_orders_assignment_cols.sql
-- ============================================================
-- Migration: Split work_assignments.assignee_staff_id into assigned_tech_id + assigned_packer_id
--            Remove orders.tester_id and orders.packer_id (assignment now in work_assignments)
-- Date: 2026-03-05

BEGIN;

-- ─────────────────────────────────────────────────────────────────────────────
-- 1. WORK_ASSIGNMENTS: rename assignee_staff_id → assigned_tech_id
--    and add assigned_packer_id
-- ─────────────────────────────────────────────────────────────────────────────

ALTER TABLE work_assignments
  RENAME COLUMN assignee_staff_id TO assigned_tech_id;

ALTER TABLE work_assignments
  ADD COLUMN IF NOT EXISTS assigned_packer_id INTEGER REFERENCES staff(id) ON DELETE SET NULL;

-- For existing PACK-type rows: move assigned_tech_id → assigned_packer_id and clear tech column.
UPDATE work_assignments
SET
  assigned_packer_id = assigned_tech_id,
  assigned_tech_id   = NULL
WHERE work_type = 'PACK'
  AND assigned_tech_id IS NOT NULL;

-- Drop old unique index (references old column name, will need recreating)
DROP INDEX IF EXISTS idx_work_assignments_active_unique;

-- Recreate the active-unique index using whichever assignee is populated
-- A single entity/work_type pair should have at most one ASSIGNED or IN_PROGRESS row
CREATE UNIQUE INDEX IF NOT EXISTS idx_work_assignments_active_unique
  ON work_assignments (entity_type, entity_id, work_type)
  WHERE status IN ('ASSIGNED', 'IN_PROGRESS');

-- Index on assigned_tech_id for fast look-ups
CREATE INDEX IF NOT EXISTS idx_work_assignments_tech_id
  ON work_assignments (assigned_tech_id)
  WHERE assigned_tech_id IS NOT NULL;

-- Index on assigned_packer_id for fast look-ups
CREATE INDEX IF NOT EXISTS idx_work_assignments_packer_id
  ON work_assignments (assigned_packer_id)
  WHERE assigned_packer_id IS NOT NULL;

-- ─────────────────────────────────────────────────────────────────────────────
-- 2. ORDERS: migrate existing tester_id / packer_id into work_assignments
--    before dropping the columns
-- ─────────────────────────────────────────────────────────────────────────────

-- Migrate tester_id → work_assignments (entity_type=ORDER, work_type=TEST)
-- Only insert if no active TEST assignment already exists for that order.
INSERT INTO work_assignments (entity_type, entity_id, work_type, assigned_tech_id, status, priority, notes)
SELECT
  'ORDER',
  o.id,
  'TEST',
  o.tester_id,
  'ASSIGNED',
  100,
  'Migrated from orders.tester_id'
FROM orders o
WHERE o.tester_id IS NOT NULL
  AND NOT EXISTS (
    SELECT 1
    FROM work_assignments wa
    WHERE wa.entity_type = 'ORDER'
      AND wa.entity_id   = o.id
      AND wa.work_type   = 'TEST'
      AND wa.status IN ('ASSIGNED', 'IN_PROGRESS')
  )
ON CONFLICT DO NOTHING;

-- Migrate packer_id → work_assignments (entity_type=ORDER, work_type=PACK)
INSERT INTO work_assignments (entity_type, entity_id, work_type, assigned_packer_id, status, priority, notes)
SELECT
  'ORDER',
  o.id,
  'PACK',
  o.packer_id,
  'ASSIGNED',
  100,
  'Migrated from orders.packer_id'
FROM orders o
WHERE o.packer_id IS NOT NULL
  AND NOT EXISTS (
    SELECT 1
    FROM work_assignments wa
    WHERE wa.entity_type = 'ORDER'
      AND wa.entity_id   = o.id
      AND wa.work_type   = 'PACK'
      AND wa.status IN ('ASSIGNED', 'IN_PROGRESS')
  )
ON CONFLICT DO NOTHING;

-- ─────────────────────────────────────────────────────────────────────────────
-- 3. DROP tester_id and packer_id from orders
-- ─────────────────────────────────────────────────────────────────────────────

-- Drop indexes that reference these columns (if they exist)
DROP INDEX IF EXISTS idx_orders_tester_id;
DROP INDEX IF EXISTS idx_orders_packer_id;

ALTER TABLE orders
  DROP COLUMN IF EXISTS tester_id,
  DROP COLUMN IF EXISTS packer_id;

COMMIT;

-- ============================================================
-- 2026-03-06_consolidate_photos_unified_table.sql
-- ============================================================
-- Migration: Create unified photos table, drop legacy photo storage
-- Date: 2026-03-06
-- No data backfill — old photo data is discarded.
-- Deploy updated API code reading/writing photos BEFORE running this script.

BEGIN;

-- ─── 1. Unified photos table ────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS photos (
  id            BIGSERIAL PRIMARY KEY,
  entity_type   TEXT      NOT NULL,
  entity_id     INTEGER   NOT NULL,
  url           TEXT      NOT NULL,
  taken_by_staff_id INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  photo_type    TEXT,
  created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  CONSTRAINT chk_photos_entity_type
    CHECK (entity_type IN ('RECEIVING', 'PACKER_LOG'))
);

-- Prevent duplicate photo rows
CREATE UNIQUE INDEX IF NOT EXISTS ux_photos_entity_url
  ON photos (entity_type, entity_id, url);

CREATE INDEX IF NOT EXISTS idx_photos_entity_created
  ON photos (entity_type, entity_id, created_at DESC);

CREATE INDEX IF NOT EXISTS idx_photos_taken_by_staff
  ON photos (taken_by_staff_id);

CREATE INDEX IF NOT EXISTS idx_photos_type
  ON photos (photo_type);

-- ─── 2. updated_at trigger ──────────────────────────────────────────────────
CREATE OR REPLACE FUNCTION fn_set_photos_updated_at()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_photos_set_updated_at ON photos;
CREATE TRIGGER trg_photos_set_updated_at
BEFORE UPDATE ON photos
FOR EACH ROW EXECUTE FUNCTION fn_set_photos_updated_at();

-- ─── 3. Polymorphic entity validation trigger ────────────────────────────────
CREATE OR REPLACE FUNCTION fn_validate_photo_entity_ref()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  IF NEW.entity_type = 'PACKER_LOG' THEN
    IF NOT EXISTS (SELECT 1 FROM packer_logs WHERE id = NEW.entity_id) THEN
      RAISE EXCEPTION 'photos.entity_id % does not exist in packer_logs', NEW.entity_id;
    END IF;
  ELSIF NEW.entity_type = 'RECEIVING' THEN
    IF NOT EXISTS (SELECT 1 FROM receiving WHERE id = NEW.entity_id) THEN
      RAISE EXCEPTION 'photos.entity_id % does not exist in receiving', NEW.entity_id;
    END IF;
  ELSE
    RAISE EXCEPTION 'Unsupported photos.entity_type: %', NEW.entity_type;
  END IF;
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_photos_validate_entity_ref ON photos;
CREATE TRIGGER trg_photos_validate_entity_ref
BEFORE INSERT OR UPDATE ON photos
FOR EACH ROW EXECUTE FUNCTION fn_validate_photo_entity_ref();

-- ─── 4. Cascade photo cleanup when parent row is deleted ────────────────────
CREATE OR REPLACE FUNCTION fn_delete_photos_on_parent_delete()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  DELETE FROM photos
  WHERE entity_type = TG_ARGV[0]
    AND entity_id   = OLD.id;
  RETURN OLD;
END;
$$;

DROP TRIGGER IF EXISTS trg_delete_photos_on_packer_log_delete ON packer_logs;
CREATE TRIGGER trg_delete_photos_on_packer_log_delete
AFTER DELETE ON packer_logs
FOR EACH ROW EXECUTE FUNCTION fn_delete_photos_on_parent_delete('PACKER_LOG');

DROP TRIGGER IF EXISTS trg_delete_photos_on_receiving_delete ON receiving;
CREATE TRIGGER trg_delete_photos_on_receiving_delete
AFTER DELETE ON receiving
FOR EACH ROW EXECUTE FUNCTION fn_delete_photos_on_parent_delete('RECEIVING');

-- ─── 5. Remove legacy photo storage ─────────────────────────────────────────
ALTER TABLE packer_logs
  DROP COLUMN IF EXISTS packer_photos_url;

DROP TABLE IF EXISTS receiving_photos;

COMMIT;

-- ============================================================
-- 2026-03-06_create_fba_lifecycle_tables.sql
-- ============================================================
-- FBA Shipment Lifecycle tables
-- Replaces the receiving WHERE target_channel='FBA' hack with an explicit
-- lifecycle: PLANNED -> READY_TO_GO -> LABEL_ASSIGNED -> SHIPPED

-- ── Enums ───────────────────────────────────────────────────────────────────

DO $$
BEGIN
  CREATE TYPE fba_shipment_status_enum AS ENUM ('PLANNED','READY_TO_GO','LABEL_ASSIGNED','SHIPPED');
EXCEPTION
  WHEN duplicate_object THEN NULL;
END $$;

DO $$
BEGIN
  CREATE TYPE fba_scan_mode_enum AS ENUM ('TECH_PREP','PACKER_VERIFY','LABEL_BIND','SHIP_CLOSE','ADMIN');
EXCEPTION
  WHEN duplicate_object THEN NULL;
END $$;

DO $$
BEGIN
  CREATE TYPE fba_scan_event_enum AS ENUM (
    'FNSKU_SCANNED','READY_MARKED','PACK_VERIFIED','LABEL_BOUND','SHIPMENT_CLOSED','ADMIN_OVERRIDE'
  );
EXCEPTION
  WHEN duplicate_object THEN NULL;
END $$;

-- ── Table 1: fba_shipments (header) ─────────────────────────────────────────
-- One row per Amazon FBA outbound shipment.  entity_id in work_assignments
-- will reference this table when entity_type = 'FBA_SHIPMENT'.

CREATE TABLE IF NOT EXISTS fba_shipments (
  id                   SERIAL PRIMARY KEY,
  shipment_ref         TEXT NOT NULL,          -- Amazon shipment ID e.g. FBA15XXXXX
  destination_fc       TEXT,                   -- Amazon fulfillment-center code
  due_date             DATE,
  status               fba_shipment_status_enum NOT NULL DEFAULT 'PLANNED',
  created_by_staff_id  INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  assigned_tech_id     INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  assigned_packer_id   INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  shipped_at           TIMESTAMPTZ,
  notes                TEXT,
  created_at           TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at           TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_fba_shipments_status
  ON fba_shipments(status, created_at DESC);

CREATE INDEX IF NOT EXISTS idx_fba_shipments_tech
  ON fba_shipments(assigned_tech_id)
  WHERE assigned_tech_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_fba_shipments_packer
  ON fba_shipments(assigned_packer_id)
  WHERE assigned_packer_id IS NOT NULL;

-- ── Table 2: fba_shipment_items (qty-bucket per FNSKU per shipment) ──────────
-- One row per FNSKU per shipment.  actual_qty increments on each tech scan.
-- Product metadata is denormalised here because fba_fnskus is truncated on
-- every sheet-sync; copying at plan time prevents history loss.

CREATE TABLE IF NOT EXISTS fba_shipment_items (
  id                    SERIAL PRIMARY KEY,
  shipment_id           INTEGER NOT NULL REFERENCES fba_shipments(id) ON DELETE CASCADE,
  fnsku                 TEXT NOT NULL,
  product_title         TEXT,
  asin                  TEXT,
  sku                   TEXT,
  expected_qty          INTEGER NOT NULL DEFAULT 0,
  actual_qty            INTEGER NOT NULL DEFAULT 0,
  status                fba_shipment_status_enum NOT NULL DEFAULT 'PLANNED',
  ready_by_staff_id     INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  ready_at              TIMESTAMPTZ,
  verified_by_staff_id  INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  verified_at           TIMESTAMPTZ,
  labeled_by_staff_id   INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  labeled_at            TIMESTAMPTZ,
  shipped_by_staff_id   INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  shipped_at            TIMESTAMPTZ,
  created_at            TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at            TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (shipment_id, fnsku)
);

CREATE INDEX IF NOT EXISTS idx_fba_items_shipment
  ON fba_shipment_items(shipment_id, status);

CREATE INDEX IF NOT EXISTS idx_fba_items_fnsku
  ON fba_shipment_items(fnsku);

-- ── Table 3: fba_label_batches (one shipping label → bundle of items) ────────

CREATE TABLE IF NOT EXISTS fba_label_batches (
  id                    SERIAL PRIMARY KEY,
  shipment_id           INTEGER NOT NULL REFERENCES fba_shipments(id) ON DELETE CASCADE,
  label_barcode         TEXT NOT NULL,
  status                TEXT NOT NULL DEFAULT 'OPEN'
                          CHECK (status IN ('OPEN','SEALED','SHIPPED')),
  labeled_by_staff_id   INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  created_at            TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at            TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (shipment_id, label_barcode)
);

CREATE INDEX IF NOT EXISTS idx_fba_label_batches_shipment
  ON fba_label_batches(shipment_id, status);

-- ── Table 4: fba_label_batch_items (junction) ────────────────────────────────

CREATE TABLE IF NOT EXISTS fba_label_batch_items (
  id         SERIAL PRIMARY KEY,
  batch_id   INTEGER NOT NULL REFERENCES fba_label_batches(id) ON DELETE CASCADE,
  item_id    INTEGER NOT NULL REFERENCES fba_shipment_items(id) ON DELETE CASCADE,
  qty        INTEGER NOT NULL DEFAULT 1,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (batch_id, item_id)
);

-- ── Table 5: fba_scan_events (immutable audit log) ───────────────────────────
-- New FNSKU scans go here instead of tech_serial_numbers with serial_type='FNSKU'.
-- Historical rows in tech_serial_numbers remain untouched.

CREATE TABLE IF NOT EXISTS fba_scan_events (
  id                   SERIAL PRIMARY KEY,
  shipment_id          INTEGER REFERENCES fba_shipments(id) ON DELETE SET NULL,
  item_id              INTEGER REFERENCES fba_shipment_items(id) ON DELETE SET NULL,
  batch_id             INTEGER REFERENCES fba_label_batches(id) ON DELETE SET NULL,
  scanned_by_staff_id  INTEGER NOT NULL REFERENCES staff(id) ON DELETE RESTRICT,
  scan_mode            fba_scan_mode_enum NOT NULL,
  event_type           fba_scan_event_enum NOT NULL,
  fnsku                TEXT,
  station              TEXT,
  metadata             JSONB,
  created_at           TIMESTAMPTZ NOT NULL DEFAULT NOW()
  -- Intentionally no updated_at — immutable audit log
);

CREATE INDEX IF NOT EXISTS idx_fba_scan_events_shipment
  ON fba_scan_events(shipment_id)
  WHERE shipment_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_fba_scan_events_item
  ON fba_scan_events(item_id)
  WHERE item_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_fba_scan_events_staff_date
  ON fba_scan_events(scanned_by_staff_id, created_at DESC);

-- ============================================================
-- 2026-03-06_fix_sku_table_columns.sql
-- ============================================================
-- Ensure sku table exists with the full schema
CREATE TABLE IF NOT EXISTS sku (
  id                      SERIAL PRIMARY KEY,
  static_sku              TEXT,
  serial_number           TEXT,
  shipping_tracking_number TEXT,
  notes                   TEXT,
  location                TEXT,
  date_time               TIMESTAMP,
  created_at              TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at              TIMESTAMP DEFAULT now()
);

-- Idempotently add any missing columns (safe to run multiple times)
ALTER TABLE sku ADD COLUMN IF NOT EXISTS shipping_tracking_number TEXT;
ALTER TABLE sku ADD COLUMN IF NOT EXISTS notes                    TEXT;
ALTER TABLE sku ADD COLUMN IF NOT EXISTS location                 TEXT;
ALTER TABLE sku ADD COLUMN IF NOT EXISTS date_time                TIMESTAMP;
ALTER TABLE sku ADD COLUMN IF NOT EXISTS created_at               TIMESTAMP DEFAULT CURRENT_TIMESTAMP;
ALTER TABLE sku ADD COLUMN IF NOT EXISTS updated_at               TIMESTAMP DEFAULT now();

-- Backfill nulls so NOT NULL can be set safely
UPDATE sku SET created_at = now() WHERE created_at IS NULL;
UPDATE sku SET updated_at = now() WHERE updated_at IS NULL;

-- Set column defaults if not already set
ALTER TABLE sku ALTER COLUMN created_at SET DEFAULT CURRENT_TIMESTAMP;
ALTER TABLE sku ALTER COLUMN updated_at SET DEFAULT now();

-- Auto-update updated_at on row changes
CREATE OR REPLACE FUNCTION set_sku_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_sku_updated_at ON sku;
CREATE TRIGGER trg_sku_updated_at
BEFORE UPDATE ON sku
FOR EACH ROW EXECUTE FUNCTION set_sku_updated_at();

