-- ============================================================
-- 2026-03-09_ebay_accounts_add_platform_zoho.sql
-- ============================================================
-- Extend ebay_accounts into a universal platform OAuth token store.
-- Adds a platform column; seeds a ZOHO_MAIN row for Zoho Inventory tokens.

ALTER TABLE ebay_accounts
  ADD COLUMN IF NOT EXISTS platform VARCHAR(20);

-- Back-fill existing eBay rows
UPDATE ebay_accounts SET platform = 'EBAY' WHERE platform IS NULL;

-- Seed placeholder Zoho row — access/refresh tokens populated by OAuth callback
INSERT INTO ebay_accounts (
  account_name,
  platform,
  access_token,
  refresh_token,
  token_expires_at,
  refresh_token_expires_at,
  is_active
) VALUES (
  'ZOHO_MAIN',
  'ZOHO',
  '',
  '',
  NOW(),
  NOW() + INTERVAL '10 years',
  true
) ON CONFLICT (account_name) DO UPDATE
    SET platform = 'ZOHO',
        updated_at = NOW();

CREATE INDEX IF NOT EXISTS idx_ebay_accounts_platform ON ebay_accounts(platform);

-- ============================================================
-- 2026-03-09_receiving_add_purchaseorder_columns.sql
-- ============================================================
-- Extend receiving + receiving_lines to support Zoho Purchase Order imports
-- (import POs into the receiving queue as PENDING expected inbound shipments)

ALTER TABLE receiving
  ADD COLUMN IF NOT EXISTS zoho_purchaseorder_id     TEXT,
  ADD COLUMN IF NOT EXISTS zoho_purchaseorder_number TEXT;

CREATE INDEX IF NOT EXISTS idx_receiving_zoho_po_id ON receiving(zoho_purchaseorder_id);

-- Additional receiving_lines columns used by PO + receive sync (idempotent)
ALTER TABLE receiving_lines
  ADD COLUMN IF NOT EXISTS zoho_purchase_receive_id TEXT,
  ADD COLUMN IF NOT EXISTS zoho_purchaseorder_id    TEXT,
  ADD COLUMN IF NOT EXISTS zoho_line_item_id        TEXT,
  ADD COLUMN IF NOT EXISTS item_name                TEXT,
  ADD COLUMN IF NOT EXISTS sku                      TEXT,
  ADD COLUMN IF NOT EXISTS quantity_received        INTEGER,
  ADD COLUMN IF NOT EXISTS quantity_expected        INTEGER,
  ADD COLUMN IF NOT EXISTS notes                    TEXT;

CREATE INDEX IF NOT EXISTS idx_receiving_lines_zoho_po_id ON receiving_lines(zoho_purchaseorder_id);

-- ============================================================
-- 2026-03-09_receiving_lines_nullable_receiving_id.sql
-- ============================================================
-- Allow receiving_lines rows that are not yet matched to a physical receiving scan.
-- Zoho PO sync creates receiving_lines with receiving_id = NULL (expected items).
-- When a package is scanned and unboxed in Mode1/Mode2, receiving_id gets set.

ALTER TABLE receiving_lines
  ALTER COLUMN receiving_id DROP NOT NULL,
  ALTER COLUMN quantity_received SET DEFAULT 0;

-- ============================================================
-- 2026-03-09_receiving_lines_workflow.sql
-- ============================================================
-- Extend receiving_lines to carry full line-level lifecycle state.
-- This is the core of the inbound workflow normalization.
--
-- Lifecycle:  EXPECTED → ARRIVED → MATCHED → UNBOXED → AWAITING_TEST
--             → IN_TEST → PASSED | FAILED → RTV | SCRAP | DONE

DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'inbound_workflow_status_enum') THEN
    CREATE TYPE inbound_workflow_status_enum AS ENUM (
      'EXPECTED',
      'ARRIVED',
      'MATCHED',
      'UNBOXED',
      'AWAITING_TEST',
      'IN_TEST',
      'PASSED',
      'FAILED',
      'RTV',
      'SCRAP',
      'DONE'
    );
  END IF;
END $$;

ALTER TABLE receiving_lines
  ADD COLUMN IF NOT EXISTS workflow_status   inbound_workflow_status_enum NOT NULL DEFAULT 'EXPECTED',
  ADD COLUMN IF NOT EXISTS needs_test        BOOLEAN NOT NULL DEFAULT FALSE,
  ADD COLUMN IF NOT EXISTS assigned_tech_id  INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS disposition_final TEXT,
  ADD COLUMN IF NOT EXISTS created_at        TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  ADD COLUMN IF NOT EXISTS updated_at        TIMESTAMPTZ NOT NULL DEFAULT NOW();

-- Index for fast tech queue lookups
CREATE INDEX IF NOT EXISTS idx_receiving_lines_workflow_status
  ON receiving_lines(workflow_status);

CREATE INDEX IF NOT EXISTS idx_receiving_lines_assigned_tech
  ON receiving_lines(assigned_tech_id)
  WHERE assigned_tech_id IS NOT NULL;

-- Auto-maintain updated_at
CREATE OR REPLACE FUNCTION fn_set_receiving_lines_updated_at()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_receiving_lines_updated_at ON receiving_lines;
CREATE TRIGGER trg_receiving_lines_updated_at
  BEFORE UPDATE ON receiving_lines
  FOR EACH ROW EXECUTE FUNCTION fn_set_receiving_lines_updated_at();

-- ============================================================
-- 2026-03-09_receiving_timestamps_to_timestamptz.sql
-- ============================================================
-- Convert naive timestamp columns in `receiving` to timezone-aware timestamptz.
-- Existing stored values were always written as America/Los_Angeles (PST/PDT),
-- so we reinterpret them as LA time before converting to UTC for storage.

ALTER TABLE receiving
  ALTER COLUMN date_time    TYPE timestamptz
    USING date_time    AT TIME ZONE 'America/Los_Angeles',
  ALTER COLUMN received_at  TYPE timestamptz
    USING received_at  AT TIME ZONE 'America/Los_Angeles',
  ALTER COLUMN unboxed_at   TYPE timestamptz
    USING unboxed_at   AT TIME ZONE 'America/Los_Angeles';

-- Verify
SELECT column_name, data_type
FROM information_schema.columns
WHERE table_name = 'receiving'
  AND column_name IN ('date_time','received_at','unboxed_at')
ORDER BY column_name;

-- ============================================================
-- 2026-03-10_add_sku_stock_work_assignments.sql
-- ============================================================
ALTER TYPE work_entity_type_enum ADD VALUE IF NOT EXISTS 'SKU_STOCK';
ALTER TYPE work_type_enum ADD VALUE IF NOT EXISTS 'STOCK_REPLENISH';

-- ============================================================
-- 2026-03-10_add_work_assignment_deadlines.sql
-- ============================================================
-- Move order deadlines from orders.ship_by_date to work_assignments.deadline_at
-- and drop the legacy orders.ship_by_date column.

BEGIN;

-- 1. Add OPEN status for canonical unassigned queue rows.
DO $$
BEGIN
  ALTER TYPE assignment_status_enum ADD VALUE IF NOT EXISTS 'OPEN';
EXCEPTION
  WHEN duplicate_object THEN NULL;
END $$;

-- 2. Add deadline_at to work_assignments.
ALTER TABLE work_assignments
  ADD COLUMN IF NOT EXISTS deadline_at TIMESTAMPTZ;

-- 3. Replace unique index to cover OPEN/ASSIGNED/IN_PROGRESS (one active row per entity/work_type).
DROP INDEX IF EXISTS ux_work_assignments_active_entity;
DROP INDEX IF EXISTS idx_work_assignments_active_unique;

CREATE UNIQUE INDEX IF NOT EXISTS ux_work_assignments_active_entity
  ON work_assignments(entity_type, entity_id, work_type)
  WHERE status IN ('OPEN', 'ASSIGNED', 'IN_PROGRESS');

-- 4. Queue/sort index for deadline-driven ordering.
CREATE INDEX IF NOT EXISTS idx_work_assignments_deadline_queue
  ON work_assignments(entity_type, work_type, status, assigned_tech_id, assigned_packer_id, deadline_at, priority, assigned_at);

-- 5. Backfill deadline_at on existing ORDER TEST/PACK rows from orders.ship_by_date.
UPDATE work_assignments wa
SET
  deadline_at = o.ship_by_date,
  updated_at  = NOW()
FROM orders o
WHERE wa.entity_type = 'ORDER'
  AND wa.entity_id   = o.id
  AND wa.work_type   IN ('TEST', 'PACK')
  AND o.ship_by_date IS NOT NULL
  AND wa.deadline_at IS DISTINCT FROM o.ship_by_date;

-- 6. Create canonical OPEN TEST rows for every order that lacks an active TEST row.
--    Covers unassigned orders and provides historical deadline source for shipped orders.
INSERT INTO work_assignments (
  entity_type,
  entity_id,
  work_type,
  assigned_tech_id,
  status,
  priority,
  deadline_at,
  notes,
  assigned_at,
  created_at,
  updated_at
)
SELECT
  'ORDER',
  o.id,
  'TEST',
  NULL,
  'OPEN',
  100,
  o.ship_by_date,
  'Canonical deadline row migrated from orders.ship_by_date',
  COALESCE(o.created_at, NOW()),
  COALESCE(o.created_at, NOW()),
  NOW()
FROM orders o
WHERE NOT EXISTS (
  SELECT 1
  FROM work_assignments wa
  WHERE wa.entity_type = 'ORDER'
    AND wa.entity_id   = o.id
    AND wa.work_type   = 'TEST'
    AND wa.status      IN ('OPEN', 'ASSIGNED', 'IN_PROGRESS')
);

-- 7. Preserve historical deadlines on completed/canceled TEST rows if they are blank.
UPDATE work_assignments wa
SET
  deadline_at = seeded.deadline_at,
  updated_at  = NOW()
FROM (
  SELECT DISTINCT ON (entity_id)
    entity_id,
    deadline_at
  FROM work_assignments
  WHERE entity_type = 'ORDER'
    AND work_type = 'TEST'
    AND deadline_at IS NOT NULL
  ORDER BY entity_id,
           CASE status WHEN 'IN_PROGRESS' THEN 1 WHEN 'ASSIGNED' THEN 2 WHEN 'OPEN' THEN 3 WHEN 'DONE' THEN 4 ELSE 5 END,
           updated_at DESC,
           id DESC
) seeded
WHERE wa.entity_type = 'ORDER'
  AND wa.work_type = 'TEST'
  AND wa.entity_id = seeded.entity_id
  AND wa.deadline_at IS NULL;

-- 8. Drop the legacy index/column now that deadline_at is populated.
DROP INDEX IF EXISTS idx_orders_ship_by_date;

ALTER TABLE orders
  DROP COLUMN IF EXISTS ship_by_date;

COMMIT;

-- ============================================================
-- 2026-03-10_attach_shipment_id.sql
-- ============================================================
-- Attach shipment_id FK to all business tables that hold a raw shipping_tracking_number.
-- This is a safe, non-destructive migration — the old TEXT columns stay untouched.
-- Existing code continues to work; new code can JOIN through shipment_id.

BEGIN;

-- 1. Add nullable FK column to each business table
ALTER TABLE orders            ADD COLUMN IF NOT EXISTS shipment_id BIGINT REFERENCES shipping_tracking_numbers(id) ON DELETE SET NULL;
ALTER TABLE tech_serial_numbers ADD COLUMN IF NOT EXISTS shipment_id BIGINT REFERENCES shipping_tracking_numbers(id) ON DELETE SET NULL;
ALTER TABLE packer_logs       ADD COLUMN IF NOT EXISTS shipment_id BIGINT REFERENCES shipping_tracking_numbers(id) ON DELETE SET NULL;
ALTER TABLE orders_exceptions ADD COLUMN IF NOT EXISTS shipment_id BIGINT REFERENCES shipping_tracking_numbers(id) ON DELETE SET NULL;
ALTER TABLE sku               ADD COLUMN IF NOT EXISTS shipment_id BIGINT REFERENCES shipping_tracking_numbers(id) ON DELETE SET NULL;

-- 2. Partial indexes — only index rows that actually have a shipment link
CREATE INDEX IF NOT EXISTS idx_orders_shipment_id            ON orders(shipment_id)            WHERE shipment_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_tech_serial_shipment_id       ON tech_serial_numbers(shipment_id) WHERE shipment_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_packer_logs_shipment_id       ON packer_logs(shipment_id)       WHERE shipment_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_orders_exceptions_shipment_id ON orders_exceptions(shipment_id) WHERE shipment_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_sku_shipment_id               ON sku(shipment_id)               WHERE shipment_id IS NOT NULL;

-- 3. Backfill shipment_id on orders by matching the normalized tracking string
--    (shipping_tracking_numbers was pre-populated by the backfill Node script)
UPDATE orders o
SET    shipment_id = stn.id
FROM   shipping_tracking_numbers stn
WHERE  stn.tracking_number_normalized
         = UPPER(REGEXP_REPLACE(COALESCE(o.shipping_tracking_number, ''), '[^A-Z0-9]', '', 'g'))
  AND  o.shipping_tracking_number IS NOT NULL
  AND  o.shipping_tracking_number <> ''
  AND  o.shipment_id IS NULL;

-- 4. Backfill tech_serial_numbers
UPDATE tech_serial_numbers tsn
SET    shipment_id = stn.id
FROM   shipping_tracking_numbers stn
WHERE  stn.tracking_number_normalized
         = UPPER(REGEXP_REPLACE(COALESCE(tsn.shipping_tracking_number, ''), '[^A-Z0-9]', '', 'g'))
  AND  tsn.shipping_tracking_number IS NOT NULL
  AND  tsn.shipping_tracking_number <> ''
  AND  tsn.shipment_id IS NULL;

-- 5. Backfill packer_logs
UPDATE packer_logs pl
SET    shipment_id = stn.id
FROM   shipping_tracking_numbers stn
WHERE  stn.tracking_number_normalized
         = UPPER(REGEXP_REPLACE(COALESCE(pl.shipping_tracking_number, ''), '[^A-Z0-9]', '', 'g'))
  AND  pl.shipping_tracking_number IS NOT NULL
  AND  pl.shipment_id IS NULL;

-- 6. Backfill orders_exceptions
UPDATE orders_exceptions oe
SET    shipment_id = stn.id
FROM   shipping_tracking_numbers stn
WHERE  stn.tracking_number_normalized
         = UPPER(REGEXP_REPLACE(COALESCE(oe.shipping_tracking_number, ''), '[^A-Z0-9]', '', 'g'))
  AND  oe.shipping_tracking_number IS NOT NULL
  AND  oe.shipment_id IS NULL;

-- 7. Backfill sku table
UPDATE sku s
SET    shipment_id = stn.id
FROM   shipping_tracking_numbers stn
WHERE  stn.tracking_number_normalized
         = UPPER(REGEXP_REPLACE(COALESCE(s.shipping_tracking_number, ''), '[^A-Z0-9]', '', 'g'))
  AND  s.shipping_tracking_number IS NOT NULL
  AND  s.shipping_tracking_number <> ''
  AND  s.shipment_id IS NULL;

COMMIT;

-- ============================================================
-- 2026-03-10_phase0_fix_lowercase_tracking.sql
-- ============================================================
-- Phase 0: Fix backfill for rows where shipping_tracking_number was stored lowercase.
-- Bug: prior SQL UPDATE used [^A-Z0-9] regex BEFORE applying UPPER(), stripping lowercase letters.
-- Fix: apply UPPER() first, then strip non-alphanum chars.

UPDATE tech_serial_numbers tsn
SET    shipment_id = stn.id
FROM   shipping_tracking_numbers stn
WHERE  stn.tracking_number_normalized =
         UPPER(REGEXP_REPLACE(UPPER(COALESCE(tsn.shipping_tracking_number, '')), '[^A-Z0-9]', '', 'g'))
  AND  tsn.shipment_id IS NULL
  AND  tsn.shipping_tracking_number IS NOT NULL
  AND  tsn.shipping_tracking_number <> '';

-- Also fix packer_logs and orders_exceptions with the same bug
UPDATE packer_logs pl
SET    shipment_id = stn.id
FROM   shipping_tracking_numbers stn
WHERE  stn.tracking_number_normalized =
         UPPER(REGEXP_REPLACE(UPPER(COALESCE(pl.shipping_tracking_number, '')), '[^A-Z0-9]', '', 'g'))
  AND  pl.shipment_id IS NULL
  AND  pl.shipping_tracking_number IS NOT NULL;

UPDATE orders_exceptions oe
SET    shipment_id = stn.id
FROM   shipping_tracking_numbers stn
WHERE  stn.tracking_number_normalized =
         UPPER(REGEXP_REPLACE(UPPER(COALESCE(oe.shipping_tracking_number, '')), '[^A-Z0-9]', '', 'g'))
  AND  oe.shipment_id IS NULL
  AND  oe.shipping_tracking_number IS NOT NULL;

-- ============================================================
-- 2026-03-10_phase1_add_scan_ref.sql
-- ============================================================
-- Phase 1: Add scan_ref to packer_logs for non-carrier scan types (SKU, FBA, CLEAN).
-- This column holds the raw scan input for rows where shipping_tracking_number is NOT
-- a carrier tracking number (so shipment_id stays NULL for those rows).
-- After all write paths are updated to use scan_ref, shipping_tracking_number can be dropped.

BEGIN;

ALTER TABLE packer_logs ADD COLUMN IF NOT EXISTS scan_ref TEXT;

-- Backfill scan_ref from shipping_tracking_number for all non-ORDERS rows
UPDATE packer_logs
SET    scan_ref = shipping_tracking_number
WHERE  tracking_type <> 'ORDERS'
  AND  scan_ref IS NULL
  AND  shipping_tracking_number IS NOT NULL;

-- For ORDERS rows where shipment_id is set, scan_ref stays NULL:
-- the raw tracking number is recoverable via JOIN shipping_tracking_numbers.tracking_number_raw

COMMIT;

-- ============================================================
-- 2026-03-10_phase4_drop_text_tracking_cols.sql
-- ============================================================
-- Phase 4: Drop duplicate shipping_tracking_number text columns.
-- ONLY run this after Phases 2 (writes) and 3 (reads) are fully deployed and verified.
-- Both tables must have zero code paths reading/writing the text column before running this.

BEGIN;

-- Verify coverage before dropping (will error if unacceptable gaps remain)
DO $$
DECLARE
  unlinked_orders_packer   INTEGER;
  unlinked_orders_tech     INTEGER;
BEGIN
  SELECT COUNT(*) INTO unlinked_orders_packer
  FROM packer_logs
  WHERE tracking_type = 'ORDERS' AND shipment_id IS NULL;

  SELECT COUNT(*) INTO unlinked_orders_tech
  FROM tech_serial_numbers
  WHERE shipment_id IS NULL
    AND UPPER(REGEXP_REPLACE(UPPER(COALESCE(shipping_tracking_number,'')), '[^A-Z0-9]','','g'))
        ~ '^1Z[A-Z0-9]{16}$|^9[0-9]{15,21}$|^[0-9]{12}$|^[0-9]{15}$|^[0-9]{20}$';

  IF unlinked_orders_packer > 0 THEN
    RAISE EXCEPTION 'Abort: % ORDERS-type packer_logs rows have no shipment_id. Run Phase 2 writes first.', unlinked_orders_packer;
  END IF;

  IF unlinked_orders_tech > 0 THEN
    RAISE EXCEPTION 'Abort: % carrier-tracking tech_serial rows have no shipment_id. Fix backfill first.', unlinked_orders_tech;
  END IF;

  RAISE NOTICE 'Coverage check passed. Proceeding with column drops.';
END $$;

-- Drop from packer_logs
ALTER TABLE packer_logs DROP COLUMN IF EXISTS shipping_tracking_number;

-- Drop from tech_serial_numbers
ALTER TABLE tech_serial_numbers DROP COLUMN IF EXISTS shipping_tracking_number;

-- Partial index ensuring ORDERS-type packer logs always have a shipment link
CREATE INDEX IF NOT EXISTS idx_packer_logs_orders_must_have_shipment
  ON packer_logs(shipment_id)
  WHERE tracking_type = 'ORDERS';

COMMIT;

-- ============================================================
-- 2026-03-10_shipping_backbone.sql
-- ============================================================
-- Phase 1: Shipping Backbone Tables
-- Two focused tables: shipment master record + append-only carrier event history

CREATE TABLE IF NOT EXISTS shipping_tracking_numbers (
  id BIGSERIAL PRIMARY KEY,

  tracking_number_raw TEXT NOT NULL,
  tracking_number_normalized TEXT NOT NULL UNIQUE,

  carrier TEXT NOT NULL,
  carrier_account_ref TEXT,
  source_system TEXT,

  latest_status_code TEXT,
  latest_status_label TEXT,
  latest_status_description TEXT,
  latest_status_category TEXT, -- LABEL_CREATED, ACCEPTED, IN_TRANSIT, OUT_FOR_DELIVERY, DELIVERED, EXCEPTION, RETURNED, UNKNOWN

  is_label_created BOOLEAN NOT NULL DEFAULT false,
  is_carrier_accepted BOOLEAN NOT NULL DEFAULT false,
  is_in_transit BOOLEAN NOT NULL DEFAULT false,
  is_out_for_delivery BOOLEAN NOT NULL DEFAULT false,
  is_delivered BOOLEAN NOT NULL DEFAULT false,
  has_exception BOOLEAN NOT NULL DEFAULT false,
  is_terminal BOOLEAN NOT NULL DEFAULT false,

  label_created_at TIMESTAMPTZ,
  carrier_accepted_at TIMESTAMPTZ,
  first_in_transit_at TIMESTAMPTZ,
  out_for_delivery_at TIMESTAMPTZ,
  delivered_at TIMESTAMPTZ,
  exception_at TIMESTAMPTZ,

  latest_event_at TIMESTAMPTZ,
  last_checked_at TIMESTAMPTZ,
  next_check_at TIMESTAMPTZ,

  check_attempt_count INTEGER NOT NULL DEFAULT 0,
  consecutive_error_count INTEGER NOT NULL DEFAULT 0,
  last_error_code TEXT,
  last_error_message TEXT,

  latest_payload JSONB,
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb,

  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE IF NOT EXISTS shipment_tracking_events (
  id BIGSERIAL PRIMARY KEY,

  shipment_id BIGINT NOT NULL REFERENCES shipping_tracking_numbers(id) ON DELETE CASCADE,

  carrier TEXT NOT NULL,
  tracking_number_normalized TEXT NOT NULL,

  external_event_id TEXT,
  external_status_code TEXT,
  external_status_label TEXT,
  external_status_description TEXT,

  normalized_status_category TEXT NOT NULL, -- LABEL_CREATED, ACCEPTED, IN_TRANSIT, OUT_FOR_DELIVERY, DELIVERED, EXCEPTION, RETURNED, UNKNOWN

  event_occurred_at TIMESTAMPTZ,
  event_recorded_at TIMESTAMPTZ NOT NULL DEFAULT now(),

  event_city TEXT,
  event_state TEXT,
  event_postal_code TEXT,
  event_country_code TEXT,

  signed_by TEXT,
  exception_code TEXT,
  exception_description TEXT,

  payload JSONB NOT NULL,

  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Indexes
CREATE INDEX IF NOT EXISTS idx_shipments_tracking_normalized
  ON shipping_tracking_numbers(tracking_number_normalized);

CREATE INDEX IF NOT EXISTS idx_shipments_next_check
  ON shipping_tracking_numbers(next_check_at)
  WHERE is_terminal = false;

CREATE INDEX IF NOT EXISTS idx_shipments_carrier
  ON shipping_tracking_numbers(carrier);

CREATE INDEX IF NOT EXISTS idx_events_shipment_id_time
  ON shipment_tracking_events(shipment_id, event_occurred_at DESC);

-- Deduplication key: same shipment + same event identity + same time
CREATE UNIQUE INDEX IF NOT EXISTS uq_events_dedupe
  ON shipment_tracking_events(
    shipment_id,
    COALESCE(external_event_id, ''),
    COALESCE(external_status_code, ''),
    COALESCE(event_occurred_at, 'epoch'::timestamptz)
  );

-- ============================================================
-- 2026-03-11_add_repair_outcome_cols.sql
-- ============================================================
-- Add repair-specific tracking columns to work_assignments.
--
-- out_of_stock : free-text description of a missing part blocking the repair
--                (mirrors orders.out_of_stock pattern; stored on the wa row
--                 so it stays with the assignment lifecycle, not the repair record)
--
-- repair_outcome : tech's description of what was found / performed when they
--                  start or complete the repair (set alongside status → IN_PROGRESS)

ALTER TABLE work_assignments
  ADD COLUMN IF NOT EXISTS out_of_stock   TEXT,
  ADD COLUMN IF NOT EXISTS repair_outcome TEXT;

-- Optional: index for dashboards that filter on out_of_stock repairs
CREATE INDEX IF NOT EXISTS idx_wa_repair_out_of_stock
  ON work_assignments (entity_type, work_type, out_of_stock)
  WHERE out_of_stock IS NOT NULL;

-- ============================================================
-- 2026-03-11_fba_fnsku_logs_unified.sql
-- ============================================================
-- Unify FNSKU activity into a shared event ledger for tech, pack, and ship flows.
-- This migration hardens fba_fnskus as the canonical FNSKU dimension, creates
-- fba_fnsku_logs, and adds nullable FBA linkage columns to tech_serial_numbers.

BEGIN;

DO $$
BEGIN
  CREATE TYPE fba_shipment_status_enum AS ENUM ('PLANNED','READY_TO_GO','LABEL_ASSIGNED','SHIPPED');
EXCEPTION
  WHEN duplicate_object THEN NULL;
END $$;

-- ── Canonical FNSKU dimension ────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS fba_fnskus (
  fnsku         TEXT PRIMARY KEY,
  product_title TEXT,
  asin          TEXT,
  sku           TEXT,
  is_active     BOOLEAN NOT NULL DEFAULT TRUE,
  last_seen_at  TIMESTAMPTZ,
  created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at    TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- If the table already existed in a looser form, add the new columns first.
ALTER TABLE fba_fnskus ADD COLUMN IF NOT EXISTS is_active BOOLEAN NOT NULL DEFAULT TRUE;
ALTER TABLE fba_fnskus ADD COLUMN IF NOT EXISTS last_seen_at TIMESTAMPTZ;
ALTER TABLE fba_fnskus ADD COLUMN IF NOT EXISTS created_at TIMESTAMPTZ NOT NULL DEFAULT NOW();
ALTER TABLE fba_fnskus ADD COLUMN IF NOT EXISTS updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW();

-- Normalize and deduplicate existing values before adding strict constraints.
UPDATE fba_fnskus
SET
  fnsku = UPPER(TRIM(COALESCE(fnsku, ''))),
  product_title = NULLIF(TRIM(COALESCE(product_title, '')), ''),
  asin = NULLIF(UPPER(TRIM(COALESCE(asin, ''))), ''),
  sku = NULLIF(TRIM(COALESCE(sku, '')), ''),
  last_seen_at = COALESCE(last_seen_at, NOW()),
  updated_at = NOW()
WHERE fnsku IS NOT NULL;

DELETE FROM fba_fnskus
WHERE COALESCE(TRIM(fnsku), '') = '';

WITH ranked AS (
  SELECT
    ctid,
    fnsku,
    ROW_NUMBER() OVER (
      PARTITION BY fnsku
      ORDER BY updated_at DESC NULLS LAST, created_at DESC NULLS LAST, ctid DESC
    ) AS rn
  FROM fba_fnskus
)
DELETE FROM fba_fnskus f
USING ranked r
WHERE f.ctid = r.ctid
  AND r.rn > 1;

ALTER TABLE fba_fnskus
  ALTER COLUMN fnsku SET NOT NULL;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM pg_constraint
    WHERE conname = 'fba_fnskus_pkey'
      AND conrelid = 'fba_fnskus'::regclass
  ) THEN
    ALTER TABLE fba_fnskus ADD CONSTRAINT fba_fnskus_pkey PRIMARY KEY (fnsku);
  END IF;
END $$;

CREATE INDEX IF NOT EXISTS idx_fba_fnskus_sku
  ON fba_fnskus(sku)
  WHERE sku IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_fba_fnskus_asin
  ON fba_fnskus(asin)
  WHERE asin IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_fba_fnskus_active
  ON fba_fnskus(is_active, updated_at DESC);

-- ── FBA shipment metadata alignment ──────────────────────────────────────────

CREATE TABLE IF NOT EXISTS fba_shipments (
  id                   SERIAL PRIMARY KEY,
  shipment_ref         TEXT NOT NULL,
  destination_fc       TEXT,
  due_date             DATE,
  status               fba_shipment_status_enum NOT NULL DEFAULT 'PLANNED',
  created_by_staff_id  INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  assigned_tech_id     INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  assigned_packer_id   INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  shipped_at           TIMESTAMPTZ,
  notes                TEXT,
  created_at           TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at           TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS fba_shipment_items (
  id                    SERIAL PRIMARY KEY,
  shipment_id           INTEGER NOT NULL REFERENCES fba_shipments(id) ON DELETE CASCADE,
  fnsku                 TEXT NOT NULL,
  product_title         TEXT,
  asin                  TEXT,
  sku                   TEXT,
  expected_qty          INTEGER NOT NULL DEFAULT 0,
  actual_qty            INTEGER NOT NULL DEFAULT 0,
  status                fba_shipment_status_enum NOT NULL DEFAULT 'PLANNED',
  ready_by_staff_id     INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  ready_at              TIMESTAMPTZ,
  verified_by_staff_id  INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  verified_at           TIMESTAMPTZ,
  labeled_by_staff_id   INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  labeled_at            TIMESTAMPTZ,
  shipped_by_staff_id   INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  shipped_at            TIMESTAMPTZ,
  created_at            TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at            TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  UNIQUE (shipment_id, fnsku)
);

ALTER TABLE fba_shipments
  ADD COLUMN IF NOT EXISTS ready_item_count INTEGER NOT NULL DEFAULT 0,
  ADD COLUMN IF NOT EXISTS packed_item_count INTEGER NOT NULL DEFAULT 0,
  ADD COLUMN IF NOT EXISTS shipped_item_count INTEGER NOT NULL DEFAULT 0;

ALTER TABLE fba_shipment_items
  ALTER COLUMN fnsku SET NOT NULL;

UPDATE fba_shipment_items
SET fnsku = UPPER(TRIM(fnsku))
WHERE fnsku IS NOT NULL
  AND fnsku <> UPPER(TRIM(fnsku));

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM pg_constraint
    WHERE conname = 'fba_shipment_items_fnsku_fkey'
      AND conrelid = 'fba_shipment_items'::regclass
  ) THEN
    ALTER TABLE fba_shipment_items
      ADD CONSTRAINT fba_shipment_items_fnsku_fkey
      FOREIGN KEY (fnsku) REFERENCES fba_fnskus(fnsku)
      ON UPDATE CASCADE
      ON DELETE RESTRICT
      NOT VALID;
  END IF;
END $$;

CREATE INDEX IF NOT EXISTS idx_fba_shipment_items_fnsku_status
  ON fba_shipment_items(fnsku, status, shipment_id);

-- ── Unified FNSKU event ledger ───────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS fba_fnsku_logs (
  id                    BIGSERIAL PRIMARY KEY,
  fnsku                 TEXT NOT NULL REFERENCES fba_fnskus(fnsku) ON UPDATE CASCADE ON DELETE RESTRICT,
  source_stage          TEXT NOT NULL CHECK (source_stage IN ('TECH', 'PACK', 'SHIP', 'ADMIN')),
  event_type            TEXT NOT NULL CHECK (event_type IN ('SCANNED', 'READY', 'VERIFIED', 'BOXED', 'ASSIGNED', 'SHIPPED', 'UNASSIGNED', 'VOID')),
  staff_id              INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  tech_serial_number_id BIGINT REFERENCES tech_serial_numbers(id) ON DELETE SET NULL,
  fba_shipment_id       INTEGER REFERENCES fba_shipments(id) ON DELETE SET NULL,
  fba_shipment_item_id  INTEGER REFERENCES fba_shipment_items(id) ON DELETE SET NULL,
  quantity              INTEGER NOT NULL DEFAULT 1 CHECK (quantity > 0),
  station               TEXT,
  notes                 TEXT,
  metadata              JSONB NOT NULL DEFAULT '{}'::jsonb,
  created_at            TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_fba_fnsku_logs_fnsku_created
  ON fba_fnsku_logs(fnsku, created_at DESC);

CREATE INDEX IF NOT EXISTS idx_fba_fnsku_logs_stage_event_created
  ON fba_fnsku_logs(source_stage, event_type, created_at DESC);

CREATE INDEX IF NOT EXISTS idx_fba_fnsku_logs_shipment_item
  ON fba_fnsku_logs(fba_shipment_id, fba_shipment_item_id);

CREATE INDEX IF NOT EXISTS idx_fba_fnsku_logs_tech_serial
  ON fba_fnsku_logs(tech_serial_number_id)
  WHERE tech_serial_number_id IS NOT NULL;

-- ── Tech serial linkage back to FBA logs/shipments ───────────────────────────

ALTER TABLE tech_serial_numbers
  ADD COLUMN IF NOT EXISTS fnsku TEXT,
  ADD COLUMN IF NOT EXISTS notes TEXT,
  ADD COLUMN IF NOT EXISTS fnsku_log_id BIGINT REFERENCES fba_fnsku_logs(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS fba_shipment_id INTEGER REFERENCES fba_shipments(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS fba_shipment_item_id INTEGER REFERENCES fba_shipment_items(id) ON DELETE SET NULL;

UPDATE tech_serial_numbers
SET fnsku = UPPER(TRIM(fnsku))
WHERE fnsku IS NOT NULL
  AND fnsku <> UPPER(TRIM(fnsku));

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM pg_constraint
    WHERE conname = 'tech_serial_numbers_fnsku_fkey'
      AND conrelid = 'tech_serial_numbers'::regclass
  ) THEN
    ALTER TABLE tech_serial_numbers
      ADD CONSTRAINT tech_serial_numbers_fnsku_fkey
      FOREIGN KEY (fnsku) REFERENCES fba_fnskus(fnsku)
      ON UPDATE CASCADE
      ON DELETE SET NULL
      NOT VALID;
  END IF;
END $$;

CREATE INDEX IF NOT EXISTS idx_tech_serial_numbers_fnsku
  ON tech_serial_numbers(fnsku)
  WHERE fnsku IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_tech_serial_numbers_fnsku_log_id
  ON tech_serial_numbers(fnsku_log_id)
  WHERE fnsku_log_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_tech_serial_numbers_fba_shipment_id
  ON tech_serial_numbers(fba_shipment_id)
  WHERE fba_shipment_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_tech_serial_numbers_fba_shipment_item_id
  ON tech_serial_numbers(fba_shipment_item_id)
  WHERE fba_shipment_item_id IS NOT NULL;

-- ── Historical backfill from tech serial scans ───────────────────────────────
-- Backfill only rows that have an FNSKU and are not already linked to a new log.

WITH inserted AS (
  INSERT INTO fba_fnsku_logs (
    fnsku,
    source_stage,
    event_type,
    staff_id,
    tech_serial_number_id,
    quantity,
    station,
    notes,
    metadata,
    created_at
  )
  SELECT
    tsn.fnsku,
    'TECH',
    'SCANNED',
    tsn.tested_by,
    tsn.id,
    1,
    'TECH_STATION',
    tsn.notes,
    jsonb_build_object(
      'backfilled', TRUE,
      'serial_number', tsn.serial_number,
      'serial_type', tsn.serial_type
    ),
    COALESCE(tsn.test_date_time::timestamptz, tsn.created_at::timestamptz, NOW())
  FROM tech_serial_numbers tsn
  WHERE tsn.fnsku IS NOT NULL
    AND tsn.fnsku <> ''
    AND tsn.fnsku_log_id IS NULL
  RETURNING id, tech_serial_number_id
)
UPDATE tech_serial_numbers tsn
SET fnsku_log_id = inserted.id
FROM inserted
WHERE tsn.id = inserted.tech_serial_number_id;

COMMIT;

-- ============================================================
-- 2026-03-11_phase5_drop_orders_is_shipped.sql
-- ============================================================
-- Phase 5: Drop orders.is_shipped
--
-- Prerequisites — ALL must be complete before running:
--   Phase 2: all WRITE paths use shipment_id (no new rows written with text tracking only)
--   Phase 3: all READ paths JOIN via stn; no query reads orders.is_shipped
--   Phase 4: shipping_tracking_number dropped from packer_logs + tech_serial_numbers
--   Audit:   rg "is_shipped|isShipped" src/ --type ts  → zero results remaining
--
-- Rationale:
--   is_shipped is a denormalized boolean that duplicates state already held in
--   shipping_tracking_numbers (is_carrier_accepted, is_in_transit, is_delivered, etc).
--   It drifts from the carrier truth and is ambiguous (label created? picked up? delivered?).
--   Derived status from stn is always current and unambiguous.
--
-- After this migration, compute is_shipped in every query as:
--   COALESCE(stn.is_carrier_accepted OR stn.is_in_transit
--            OR stn.is_out_for_delivery OR stn.is_delivered, false)
--
-- See: 2026-03-11_shipment_status_migration_DECISION.md

BEGIN;

DO $$
DECLARE
  shipped_count INTEGER;
  col_exists    BOOLEAN;
BEGIN
  SELECT EXISTS (
    SELECT 1
    FROM   information_schema.columns
    WHERE  table_name  = 'orders'
      AND  column_name = 'is_shipped'
  ) INTO col_exists;

  IF NOT col_exists THEN
    RAISE NOTICE 'orders.is_shipped does not exist — nothing to do.';
    RETURN;
  END IF;

  SELECT COUNT(*) INTO shipped_count FROM orders WHERE is_shipped = true;
  RAISE NOTICE 'orders.is_shipped = true on % rows (informational)', shipped_count;

  -- Sanity: confirm shipping_tracking_numbers has shipments for those rows
  -- (if this is 0 and shipped_count > 0, derived status may differ from current boolean)
  DECLARE
    linked_shipped INTEGER;
  BEGIN
    SELECT COUNT(*) INTO linked_shipped
    FROM   orders o
    JOIN   shipping_tracking_numbers stn ON stn.id = o.shipment_id
    WHERE  o.is_shipped = true
      AND  (stn.is_carrier_accepted OR stn.is_in_transit
            OR stn.is_out_for_delivery OR stn.is_delivered);

    RAISE NOTICE '% of those rows have matching stn carrier-accepted/in-transit/delivered status',
                 linked_shipped;
  END;
END $$;

ALTER TABLE orders DROP COLUMN IF EXISTS is_shipped;

COMMIT;

-- ============================================================
-- 2026-03-12_backfill_station_activity_logs.sql
-- ============================================================
BEGIN;

INSERT INTO station_activity_logs (
  station,
  activity_type,
  shipment_id,
  scan_ref,
  staff_id,
  notes,
  metadata,
  created_at,
  updated_at
)
SELECT
  'TECH',
  'TRACKING_SCANNED',
  tsn.shipment_id,
  tsn.scan_ref,
  tsn.tested_by,
  tsn.notes,
  '{}'::jsonb,
  COALESCE(tsn.created_at, NOW()),
  COALESCE(tsn.updated_at, tsn.created_at, NOW())
FROM tech_serial_numbers tsn
WHERE (tsn.serial_number IS NULL OR BTRIM(tsn.serial_number) = '')
  AND (tsn.shipment_id IS NOT NULL OR COALESCE(tsn.scan_ref, '') <> '')
  AND NOT EXISTS (
    SELECT 1
    FROM station_activity_logs sal
    WHERE sal.station = 'TECH'
      AND sal.activity_type = 'TRACKING_SCANNED'
      AND sal.staff_id IS NOT DISTINCT FROM tsn.tested_by
      AND (
        (tsn.shipment_id IS NOT NULL AND sal.shipment_id = tsn.shipment_id)
        OR (
          COALESCE(tsn.scan_ref, '') <> ''
          AND RIGHT(regexp_replace(UPPER(COALESCE(sal.scan_ref, '')), '[^A-Z0-9]', '', 'g'), 18) =
              RIGHT(regexp_replace(UPPER(COALESCE(tsn.scan_ref, '')), '[^A-Z0-9]', '', 'g'), 18)
        )
      )
  );

INSERT INTO station_activity_logs (
  station,
  activity_type,
  shipment_id,
  scan_ref,
  fnsku,
  staff_id,
  fba_shipment_id,
  fba_shipment_item_id,
  tech_serial_number_id,
  notes,
  metadata,
  created_at,
  updated_at
)
SELECT
  'TECH',
  'SERIAL_ADDED',
  tsn.shipment_id,
  tsn.scan_ref,
  tsn.fnsku,
  tsn.tested_by,
  tsn.fba_shipment_id,
  tsn.fba_shipment_item_id,
  tsn.id,
  tsn.notes,
  jsonb_build_object(
    'serial_number', tsn.serial_number,
    'fnsku_log_id', tsn.fnsku_log_id
  ),
  COALESCE(tsn.created_at, NOW()),
  COALESCE(tsn.updated_at, tsn.created_at, NOW())
FROM tech_serial_numbers tsn
WHERE tsn.serial_number IS NOT NULL
  AND BTRIM(tsn.serial_number) <> ''
  AND NOT EXISTS (
    SELECT 1
    FROM station_activity_logs sal
    WHERE sal.station = 'TECH'
      AND sal.activity_type = 'SERIAL_ADDED'
      AND sal.tech_serial_number_id = tsn.id
  );

INSERT INTO station_activity_logs (
  station,
  activity_type,
  scan_ref,
  fnsku,
  staff_id,
  fba_shipment_id,
  fba_shipment_item_id,
  notes,
  metadata,
  created_at,
  updated_at
)
SELECT
  CASE l.source_stage WHEN 'TECH' THEN 'TECH' WHEN 'PACK' THEN 'PACK' ELSE 'ADMIN' END,
  CASE
    WHEN l.source_stage = 'TECH' AND l.event_type = 'SCANNED' THEN 'FNSKU_SCANNED'
    WHEN l.source_stage = 'PACK' AND l.event_type IN ('READY', 'VERIFIED', 'BOXED') THEN 'FBA_READY'
    ELSE 'PACK_SCAN'
  END,
  l.fnsku,
  l.fnsku,
  l.staff_id,
  l.fba_shipment_id,
  l.fba_shipment_item_id,
  l.notes,
  COALESCE(l.metadata, '{}'::jsonb) || jsonb_build_object('fnsku_log_id', l.id),
  l.created_at,
  l.created_at
FROM fba_fnsku_logs l
WHERE l.source_stage IN ('TECH', 'PACK')
  AND l.event_type IN ('SCANNED', 'READY', 'VERIFIED', 'BOXED')
  AND NOT EXISTS (
    SELECT 1
    FROM station_activity_logs sal
    WHERE sal.station = CASE l.source_stage WHEN 'TECH' THEN 'TECH' WHEN 'PACK' THEN 'PACK' ELSE 'ADMIN' END
      AND sal.fnsku = l.fnsku
      AND sal.staff_id IS NOT DISTINCT FROM l.staff_id
      AND sal.created_at = l.created_at
      AND sal.activity_type = CASE
        WHEN l.source_stage = 'TECH' AND l.event_type = 'SCANNED' THEN 'FNSKU_SCANNED'
        WHEN l.source_stage = 'PACK' AND l.event_type IN ('READY', 'VERIFIED', 'BOXED') THEN 'FBA_READY'
        ELSE 'PACK_SCAN'
      END
  );

INSERT INTO station_activity_logs (
  station,
  activity_type,
  shipment_id,
  scan_ref,
  staff_id,
  packer_log_id,
  notes,
  metadata,
  created_at,
  updated_at
)
SELECT
  'PACK',
  CASE WHEN pl.tracking_type = 'ORDERS' THEN 'PACK_COMPLETED' ELSE 'PACK_SCAN' END,
  pl.shipment_id,
  pl.scan_ref,
  pl.packed_by,
  pl.id,
  NULL,
  jsonb_build_object('tracking_type', pl.tracking_type),
  COALESCE(pl.created_at, NOW()),
  COALESCE(pl.updated_at, pl.created_at, NOW())
FROM packer_logs pl
WHERE NOT EXISTS (
  SELECT 1
  FROM station_activity_logs sal
  WHERE sal.station = 'PACK'
    AND sal.packer_log_id = pl.id
);

COMMIT;

-- ============================================================
-- 2026-03-12_close_done_repair_work_assignments.sql
-- ============================================================
-- Close active REPAIR work_assignments for repair_service rows already marked Done.
--
-- Why:
-- Some historical repairs were marked Done in repair_service but their unified
-- work_assignments row remained ASSIGNED / IN_PROGRESS. Work-order queries join
-- active REPAIR assignments, so those stale rows keep appearing in the repair
-- work-order queue.
--
-- Scope:
-- Only update assigned REPAIR work assignments tied to repair_service.status='Done'.

UPDATE work_assignments wa
SET
  status = 'DONE',
  completed_at = COALESCE(wa.completed_at, NOW()),
  updated_at = NOW()
FROM repair_service rs
WHERE wa.entity_type = 'REPAIR'
  AND wa.work_type = 'REPAIR'
  AND wa.entity_id = rs.id
  AND wa.status IN ('OPEN', 'ASSIGNED', 'IN_PROGRESS')
  AND wa.assigned_tech_id IS NOT NULL
  AND COALESCE(rs.status, '') = 'Done';

-- ============================================================
-- 2026-03-12_close_shipped_order_work_assignments.sql
-- ============================================================
-- Close active ORDER work_assignments for orders already shipped.
--
-- Why:
-- Shipped state is derived from shipping_tracking_numbers. Historical ORDER
-- TEST/PACK assignments can remain OPEN / ASSIGNED / IN_PROGRESS after the
-- carrier marks the shipment in transit / delivered, which leaves stale rows
-- hanging around in work-order style views.
--
-- Scope:
-- Mark active ORDER assignments DONE when the linked shipment is already in a
-- shipped carrier state.

UPDATE work_assignments wa
SET
  status = 'DONE',
  completed_at = COALESCE(wa.completed_at, NOW()),
  updated_at = NOW()
FROM orders o
JOIN shipping_tracking_numbers stn ON stn.id = o.shipment_id
WHERE wa.entity_type = 'ORDER'
  AND wa.entity_id = o.id
  AND wa.work_type IN ('TEST', 'PACK')
  AND wa.status IN ('OPEN', 'ASSIGNED', 'IN_PROGRESS')
  AND (
    COALESCE(stn.is_carrier_accepted, false)
    OR COALESCE(stn.is_in_transit, false)
    OR COALESCE(stn.is_out_for_delivery, false)
    OR COALESCE(stn.is_delivered, false)
  );

