-- 2026-03-27_repair_signature_customers.sql
-- ============================================================
-- Migration: Repair service digital signature + customer FK linking
-- 1. Add entity_type/entity_id to customers for polymorphic linking
-- 2. Add customer_id FK to repair_service
-- 3. Create documents table (generic, scalable)

BEGIN;

-- 1. Customers: polymorphic entity linking
ALTER TABLE customers
  ADD COLUMN IF NOT EXISTS entity_type TEXT,
  ADD COLUMN IF NOT EXISTS entity_id   INTEGER;

CREATE INDEX IF NOT EXISTS idx_customers_entity
  ON customers(entity_type, entity_id)
  WHERE entity_type IS NOT NULL;

-- 2. Repair service: FK to customers
ALTER TABLE repair_service
  ADD COLUMN IF NOT EXISTS customer_id INTEGER REFERENCES customers(id) ON DELETE SET NULL;

CREATE INDEX IF NOT EXISTS idx_repair_service_customer_id
  ON repair_service(customer_id)
  WHERE customer_id IS NOT NULL;

-- 3. Documents table (generic — works for repair agreements, pickup forms, etc.)
CREATE TABLE IF NOT EXISTS documents (
  id            SERIAL PRIMARY KEY,
  entity_type   TEXT NOT NULL,                  -- 'REPAIR', 'ORDER', etc.
  entity_id     INTEGER NOT NULL,               -- FK to the entity
  document_type TEXT NOT NULL DEFAULT 'intake_agreement',  -- 'intake_agreement', 'pickup_agreement', etc.
  signature_url TEXT,                            -- Vercel Blob URL for PNG signature
  signer_name   TEXT,
  signed_at     TIMESTAMPTZ,
  document_data JSONB NOT NULL DEFAULT '{}',     -- Snapshot of document content at time of signing
  created_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at    TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_documents_entity
  ON documents(entity_type, entity_id);

COMMIT;

-- ============================================================
-- 2026-03-27_sal_sot_phase1.sql
-- ============================================================
-- Phase 1: SAL as Single Source of Truth
-- (a) Backfill context_station_activity_log_id on tech_serial_numbers where NULL
-- (b) Add station_activity_log_id FK to fba_fnsku_logs and backfill

BEGIN;

-- ============================================================================
-- (a) Backfill tech_serial_numbers.context_station_activity_log_id
-- ============================================================================

-- Strategy 1: Match via SERIAL_ADDED SAL that references this TSN row
UPDATE tech_serial_numbers tsn
SET context_station_activity_log_id = sub.sal_id
FROM (
  SELECT DISTINCT ON (sal.tech_serial_number_id)
    sal.tech_serial_number_id AS tsn_id,
    sal.id AS sal_id
  FROM station_activity_logs sal
  WHERE sal.activity_type = 'SERIAL_ADDED'
    AND sal.tech_serial_number_id IS NOT NULL
  ORDER BY sal.tech_serial_number_id, sal.created_at DESC
) sub
WHERE tsn.id = sub.tsn_id
  AND tsn.context_station_activity_log_id IS NULL;

-- Strategy 2: For FNSKU rows, find FNSKU_SCANNED SAL via fnsku_log_id in metadata
UPDATE tech_serial_numbers tsn
SET context_station_activity_log_id = sub.sal_id
FROM (
  SELECT DISTINCT ON (tsn2.id)
    tsn2.id AS tsn_id,
    sal.id AS sal_id
  FROM tech_serial_numbers tsn2
  JOIN station_activity_logs sal
    ON sal.activity_type = 'FNSKU_SCANNED'
    AND sal.station = 'TECH'
    AND (NULLIF(TRIM(sal.metadata->>'fnsku_log_id'), ''))::bigint = tsn2.fnsku_log_id
  WHERE tsn2.context_station_activity_log_id IS NULL
    AND tsn2.fnsku_log_id IS NOT NULL
  ORDER BY tsn2.id, sal.created_at DESC
) sub
WHERE tsn.id = sub.tsn_id
  AND tsn.context_station_activity_log_id IS NULL;

-- Strategy 3: For carrier tracking rows, find TRACKING_SCANNED SAL by shipment_id + staff
UPDATE tech_serial_numbers tsn
SET context_station_activity_log_id = sub.sal_id
FROM (
  SELECT DISTINCT ON (tsn2.id)
    tsn2.id AS tsn_id,
    sal.id AS sal_id
  FROM tech_serial_numbers tsn2
  JOIN station_activity_logs sal
    ON sal.activity_type = 'TRACKING_SCANNED'
    AND sal.station = 'TECH'
    AND sal.shipment_id = tsn2.shipment_id
    AND sal.staff_id = tsn2.tested_by
  WHERE tsn2.context_station_activity_log_id IS NULL
    AND tsn2.shipment_id IS NOT NULL
  ORDER BY tsn2.id, sal.created_at DESC
) sub
WHERE tsn.id = sub.tsn_id
  AND tsn.context_station_activity_log_id IS NULL;

-- ============================================================================
-- (b) Add station_activity_log_id to fba_fnsku_logs
-- ============================================================================

-- Add the column (nullable initially for backfill)
ALTER TABLE fba_fnsku_logs
  ADD COLUMN IF NOT EXISTS station_activity_log_id INTEGER REFERENCES station_activity_logs(id) ON DELETE SET NULL;

-- Backfill: match TECH FNSKU_SCANNED SAL rows by fnsku + staff_id + timestamp proximity
UPDATE fba_fnsku_logs fl
SET station_activity_log_id = sub.sal_id
FROM (
  SELECT DISTINCT ON (fl2.id)
    fl2.id AS fl_id,
    sal.id AS sal_id
  FROM fba_fnsku_logs fl2
  JOIN station_activity_logs sal
    ON sal.activity_type = 'FNSKU_SCANNED'
    AND sal.station = 'TECH'
    AND sal.fnsku = fl2.fnsku
    AND sal.staff_id = fl2.staff_id
    AND sal.created_at BETWEEN fl2.created_at - INTERVAL '10 seconds' AND fl2.created_at + INTERVAL '10 seconds'
  WHERE fl2.source_stage = 'TECH'
    AND fl2.station_activity_log_id IS NULL
  ORDER BY fl2.id, ABS(EXTRACT(EPOCH FROM (sal.created_at - fl2.created_at)))
) sub
WHERE fl.id = sub.fl_id
  AND fl.station_activity_log_id IS NULL;

-- Backfill: also try matching via SAL metadata.fnsku_log_id
UPDATE fba_fnsku_logs fl
SET station_activity_log_id = sub.sal_id
FROM (
  SELECT DISTINCT ON (fl2.id)
    fl2.id AS fl_id,
    sal.id AS sal_id
  FROM fba_fnsku_logs fl2
  JOIN station_activity_logs sal
    ON sal.station = 'TECH'
    AND (NULLIF(TRIM(sal.metadata->>'fnsku_log_id'), ''))::bigint = fl2.id
  WHERE fl2.station_activity_log_id IS NULL
  ORDER BY fl2.id, sal.created_at DESC
) sub
WHERE fl.id = sub.fl_id
  AND fl.station_activity_log_id IS NULL;

-- Create index for the FK join
CREATE INDEX IF NOT EXISTS idx_fba_fnsku_logs_sal_id
  ON fba_fnsku_logs (station_activity_log_id)
  WHERE station_activity_log_id IS NOT NULL;

-- Create index for TSN -> SAL lookup (improve join performance)
CREATE INDEX IF NOT EXISTS idx_tsn_context_sal_id
  ON tech_serial_numbers (context_station_activity_log_id)
  WHERE context_station_activity_log_id IS NOT NULL;

COMMIT;

-- ============================================================
-- 2026-03-28_create_pipeline_tables.sql
-- ============================================================
-- ============================================================
-- AI Training Pipeline Tables
-- Created: 2026-03-28
--
-- Creates 5 tables and 3 enums for the self-improving code pipeline.
-- Safe to re-run: uses IF NOT EXISTS on everything.
-- ============================================================

-- Enums
DO $$ BEGIN
  CREATE TYPE training_sample_status AS ENUM ('raw', 'rated', 'queued', 'trained', 'rejected');
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

DO $$ BEGIN
  CREATE TYPE pipeline_task_source AS ENUM ('typecheck', 'lint', 'test_failure', 'todo_comment', 'manual');
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

DO $$ BEGIN
  CREATE TYPE training_run_status AS ENUM ('pending', 'running', 'completed', 'failed');
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

-- 1. training_samples — raw + rated training pairs from pipeline, commits, chat
CREATE TABLE IF NOT EXISTS training_samples (
  id              SERIAL PRIMARY KEY,
  instruction     TEXT NOT NULL,
  input_context   TEXT,
  output          TEXT NOT NULL,
  source          VARCHAR(50) NOT NULL,
  repo            VARCHAR(200),
  file_paths      JSONB,
  commit_sha      VARCHAR(40),
  status          training_sample_status NOT NULL DEFAULT 'raw',
  rating          INTEGER,
  auto_score      NUMERIC,
  tests_pass      BOOLEAN,
  training_run_id INTEGER,
  created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  rated_at        TIMESTAMPTZ
);

CREATE INDEX IF NOT EXISTS training_samples_status_idx  ON training_samples (status);
CREATE INDEX IF NOT EXISTS training_samples_rating_idx  ON training_samples (rating);

-- 2. training_runs — fine-tuning job records
CREATE TABLE IF NOT EXISTS training_runs (
  id               SERIAL PRIMARY KEY,
  base_model       VARCHAR(200) NOT NULL,
  adapter_name     VARCHAR(200),
  lora_rank        INTEGER DEFAULT 16,
  learning_rate    NUMERIC DEFAULT 0.0002,
  epochs           INTEGER DEFAULT 3,
  sample_count     INTEGER,
  status           training_run_status NOT NULL DEFAULT 'pending',
  train_loss       NUMERIC,
  eval_loss        NUMERIC,
  duration_seconds INTEGER,
  adapter_path     TEXT,
  device_id        VARCHAR(50),
  started_at       TIMESTAMPTZ,
  completed_at     TIMESTAMPTZ,
  created_at       TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  error_log        TEXT
);

-- 3. model_versions — registered adapters with promotion flag
CREATE TABLE IF NOT EXISTS model_versions (
  id           SERIAL PRIMARY KEY,
  run_id       INTEGER REFERENCES training_runs(id),
  version      VARCHAR(50) NOT NULL,
  base_model   VARCHAR(200) NOT NULL,
  adapter_path TEXT NOT NULL,
  eval_score   NUMERIC,
  promoted     BOOLEAN NOT NULL DEFAULT FALSE,
  promoted_at  TIMESTAMPTZ,
  created_at   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- 4. pipeline_tasks — discovered tasks with dedup and retry tracking
CREATE TABLE IF NOT EXISTS pipeline_tasks (
  id              SERIAL PRIMARY KEY,
  task_hash       VARCHAR(16) NOT NULL UNIQUE,
  title           VARCHAR(300) NOT NULL,
  source          pipeline_task_source NOT NULL,
  description     TEXT NOT NULL,
  file_paths      JSONB NOT NULL,
  context         TEXT,
  priority        INTEGER NOT NULL DEFAULT 3,
  status          VARCHAR(20) NOT NULL DEFAULT 'pending',
  attempts        INTEGER NOT NULL DEFAULT 0,
  last_attempt_at TIMESTAMPTZ,
  resolved_at     TIMESTAMPTZ,
  result_branch   VARCHAR(200),
  result_rating   INTEGER,
  created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS pipeline_tasks_status_idx   ON pipeline_tasks (status);
CREATE INDEX IF NOT EXISTS pipeline_tasks_priority_idx ON pipeline_tasks (priority);

-- 5. pipeline_cycles — per-cycle execution metrics
CREATE TABLE IF NOT EXISTS pipeline_cycles (
  id                SERIAL PRIMARY KEY,
  tasks_discovered  INTEGER NOT NULL DEFAULT 0,
  tasks_attempted   INTEGER NOT NULL DEFAULT 0,
  tasks_passed      INTEGER NOT NULL DEFAULT 0,
  tasks_failed      INTEGER NOT NULL DEFAULT 0,
  samples_collected INTEGER NOT NULL DEFAULT 0,
  duration_seconds  INTEGER,
  started_at        TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  completed_at      TIMESTAMPTZ
);

-- FK from training_samples back to training_runs (deferred to avoid ordering issues)
DO $$ BEGIN
  ALTER TABLE training_samples
    ADD CONSTRAINT training_samples_run_fk
    FOREIGN KEY (training_run_id) REFERENCES training_runs(id);
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

