-- 2026-03-31_create_audit_logs.sql
-- ============================================================
BEGIN;

CREATE TABLE IF NOT EXISTS audit_logs (
  id BIGSERIAL PRIMARY KEY,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  actor_staff_id INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  actor_role TEXT,
  source TEXT NOT NULL,
  action TEXT NOT NULL,
  entity_type TEXT NOT NULL,
  entity_id TEXT NOT NULL,
  station_activity_log_id INTEGER REFERENCES station_activity_logs(id) ON DELETE SET NULL,
  request_id TEXT,
  ip_address TEXT,
  user_agent TEXT,
  before_data JSONB,
  after_data JSONB,
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb
);

CREATE INDEX IF NOT EXISTS idx_audit_logs_created_at
  ON audit_logs (created_at DESC);

CREATE INDEX IF NOT EXISTS idx_audit_logs_entity_created
  ON audit_logs (entity_type, entity_id, created_at DESC);

CREATE INDEX IF NOT EXISTS idx_audit_logs_actor_created
  ON audit_logs (actor_staff_id, created_at DESC);

CREATE INDEX IF NOT EXISTS idx_audit_logs_action_created
  ON audit_logs (action, created_at DESC);

CREATE INDEX IF NOT EXISTS idx_audit_logs_sal
  ON audit_logs (station_activity_log_id);

COMMIT;

-- ============================================================
-- 2026-03-31_create_operations_kpi_rollups.sql
-- ============================================================
BEGIN;

-- Canonical state cursor for incremental rollup jobs.
CREATE TABLE IF NOT EXISTS operations_kpi_rollup_state (
  key TEXT PRIMARY KEY,
  last_processed_at TIMESTAMPTZ NOT NULL DEFAULT '1970-01-01 00:00:00+00',
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

INSERT INTO operations_kpi_rollup_state (key, last_processed_at)
VALUES ('audit_logs', '1970-01-01 00:00:00+00')
ON CONFLICT (key) DO NOTHING;

CREATE TABLE IF NOT EXISTS operations_kpi_rollups_hourly (
  bucket_start TIMESTAMPTZ NOT NULL,
  environment TEXT NOT NULL DEFAULT 'prod',
  source TEXT NOT NULL,
  action_type TEXT NOT NULL,
  actor_staff_key INTEGER NOT NULL DEFAULT -1,
  actor_staff_id INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  event_count INTEGER NOT NULL DEFAULT 0,
  error_count INTEGER NOT NULL DEFAULT 0,
  warning_count INTEGER NOT NULL DEFAULT 0,
  unique_entities INTEGER NOT NULL DEFAULT 0,
  first_event_at TIMESTAMPTZ,
  last_event_at TIMESTAMPTZ,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (bucket_start, environment, source, action_type, actor_staff_key),
  CONSTRAINT chk_operations_kpi_hourly_actor_key
    CHECK (actor_staff_key = COALESCE(actor_staff_id, -1))
);

CREATE TABLE IF NOT EXISTS operations_kpi_rollups_daily (
  bucket_start DATE NOT NULL,
  environment TEXT NOT NULL DEFAULT 'prod',
  source TEXT NOT NULL,
  action_type TEXT NOT NULL,
  actor_staff_key INTEGER NOT NULL DEFAULT -1,
  actor_staff_id INTEGER REFERENCES staff(id) ON DELETE SET NULL,
  event_count INTEGER NOT NULL DEFAULT 0,
  error_count INTEGER NOT NULL DEFAULT 0,
  warning_count INTEGER NOT NULL DEFAULT 0,
  unique_entities INTEGER NOT NULL DEFAULT 0,
  first_event_at TIMESTAMPTZ,
  last_event_at TIMESTAMPTZ,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (bucket_start, environment, source, action_type, actor_staff_key),
  CONSTRAINT chk_operations_kpi_daily_actor_key
    CHECK (actor_staff_key = COALESCE(actor_staff_id, -1))
);

CREATE INDEX IF NOT EXISTS idx_operations_kpi_hourly_bucket_desc
  ON operations_kpi_rollups_hourly (bucket_start DESC);
CREATE INDEX IF NOT EXISTS idx_operations_kpi_hourly_env_bucket_desc
  ON operations_kpi_rollups_hourly (environment, bucket_start DESC);
CREATE INDEX IF NOT EXISTS idx_operations_kpi_hourly_source_bucket_desc
  ON operations_kpi_rollups_hourly (source, bucket_start DESC);
CREATE INDEX IF NOT EXISTS idx_operations_kpi_hourly_actor_bucket_desc
  ON operations_kpi_rollups_hourly (actor_staff_id, bucket_start DESC);

CREATE INDEX IF NOT EXISTS idx_operations_kpi_daily_bucket_desc
  ON operations_kpi_rollups_daily (bucket_start DESC);
CREATE INDEX IF NOT EXISTS idx_operations_kpi_daily_env_bucket_desc
  ON operations_kpi_rollups_daily (environment, bucket_start DESC);
CREATE INDEX IF NOT EXISTS idx_operations_kpi_daily_source_bucket_desc
  ON operations_kpi_rollups_daily (source, bucket_start DESC);
CREATE INDEX IF NOT EXISTS idx_operations_kpi_daily_actor_bucket_desc
  ON operations_kpi_rollups_daily (actor_staff_id, bucket_start DESC);

-- Recompute rollups over an explicit time window.
CREATE OR REPLACE FUNCTION refresh_operations_kpi_rollups(
  p_from TIMESTAMPTZ,
  p_to TIMESTAMPTZ
)
RETURNS TABLE (hourly_rows INTEGER, daily_rows INTEGER)
LANGUAGE plpgsql
AS $$
DECLARE
  v_hourly_rows INTEGER := 0;
  v_daily_rows INTEGER := 0;
BEGIN
  IF p_from IS NULL OR p_to IS NULL THEN
    RAISE EXCEPTION 'refresh_operations_kpi_rollups requires non-null p_from and p_to';
  END IF;

  IF p_to <= p_from THEN
    RAISE EXCEPTION 'refresh_operations_kpi_rollups requires p_to > p_from (got %, %)', p_from, p_to;
  END IF;

  WITH audit_base AS (
    SELECT
      date_trunc('hour', al.created_at) AS hour_bucket,
      date_trunc('day', al.created_at)::date AS day_bucket,
      'prod'::text AS environment,
      COALESCE(NULLIF(al.source, ''), NULLIF(al.metadata->>'source', ''), 'unknown') AS source,
      al.action AS action_type,
      al.actor_staff_id,
      al.created_at,
      al.entity_type,
      al.entity_id,
      lower(COALESCE(al.metadata->>'severity', '')) AS severity
    FROM audit_logs al
    WHERE al.created_at >= p_from
      AND al.created_at < p_to
  ),
  hourly_agg AS (
    SELECT
      hour_bucket AS bucket_start,
      environment,
      source,
      action_type,
      COALESCE(actor_staff_id, -1) AS actor_staff_key,
      actor_staff_id,
      COUNT(*)::integer AS event_count,
      SUM(
        CASE
          WHEN severity = 'error'
            OR action_type ILIKE '%ERROR%'
            OR action_type ILIKE '%FAILED%'
            OR action_type ILIKE '%EXCEPTION%'
          THEN 1 ELSE 0
        END
      )::integer AS error_count,
      SUM(
        CASE
          WHEN severity = 'warning'
            OR action_type ILIKE '%WARN%'
            OR action_type ILIKE '%RETRY%'
            OR action_type ILIKE '%AT_RISK%'
          THEN 1 ELSE 0
        END
      )::integer AS warning_count,
      COUNT(DISTINCT (entity_type || ':' || entity_id)) FILTER (
        WHERE entity_type IS NOT NULL
          AND entity_type <> ''
          AND entity_id IS NOT NULL
          AND entity_id <> ''
      )::integer AS unique_entities,
      MIN(created_at) AS first_event_at,
      MAX(created_at) AS last_event_at
    FROM audit_base
    GROUP BY 1, 2, 3, 4, 5, 6
  ),
  upsert_hourly AS (
    INSERT INTO operations_kpi_rollups_hourly (
      bucket_start,
      environment,
      source,
      action_type,
      actor_staff_key,
      actor_staff_id,
      event_count,
      error_count,
      warning_count,
      unique_entities,
      first_event_at,
      last_event_at,
      updated_at
    )
    SELECT
      bucket_start,
      environment,
      source,
      action_type,
      actor_staff_key,
      actor_staff_id,
      event_count,
      error_count,
      warning_count,
      unique_entities,
      first_event_at,
      last_event_at,
      NOW()
    FROM hourly_agg
    ON CONFLICT (bucket_start, environment, source, action_type, actor_staff_key)
    DO UPDATE SET
      actor_staff_id = EXCLUDED.actor_staff_id,
      event_count = EXCLUDED.event_count,
      error_count = EXCLUDED.error_count,
      warning_count = EXCLUDED.warning_count,
      unique_entities = EXCLUDED.unique_entities,
      first_event_at = EXCLUDED.first_event_at,
      last_event_at = EXCLUDED.last_event_at,
      updated_at = NOW()
    RETURNING 1
  )
  SELECT COUNT(*)::integer INTO v_hourly_rows FROM upsert_hourly;

  WITH audit_base AS (
    SELECT
      date_trunc('day', al.created_at)::date AS day_bucket,
      'prod'::text AS environment,
      COALESCE(NULLIF(al.source, ''), NULLIF(al.metadata->>'source', ''), 'unknown') AS source,
      al.action AS action_type,
      al.actor_staff_id,
      al.created_at,
      al.entity_type,
      al.entity_id,
      lower(COALESCE(al.metadata->>'severity', '')) AS severity
    FROM audit_logs al
    WHERE al.created_at >= p_from
      AND al.created_at < p_to
  ),
  daily_agg AS (
    SELECT
      day_bucket AS bucket_start,
      environment,
      source,
      action_type,
      COALESCE(actor_staff_id, -1) AS actor_staff_key,
      actor_staff_id,
      COUNT(*)::integer AS event_count,
      SUM(
        CASE
          WHEN severity = 'error'
            OR action_type ILIKE '%ERROR%'
            OR action_type ILIKE '%FAILED%'
            OR action_type ILIKE '%EXCEPTION%'
          THEN 1 ELSE 0
        END
      )::integer AS error_count,
      SUM(
        CASE
          WHEN severity = 'warning'
            OR action_type ILIKE '%WARN%'
            OR action_type ILIKE '%RETRY%'
            OR action_type ILIKE '%AT_RISK%'
          THEN 1 ELSE 0
        END
      )::integer AS warning_count,
      COUNT(DISTINCT (entity_type || ':' || entity_id)) FILTER (
        WHERE entity_type IS NOT NULL
          AND entity_type <> ''
          AND entity_id IS NOT NULL
          AND entity_id <> ''
      )::integer AS unique_entities,
      MIN(created_at) AS first_event_at,
      MAX(created_at) AS last_event_at
    FROM audit_base
    GROUP BY 1, 2, 3, 4, 5, 6
  ),
  upsert_daily AS (
    INSERT INTO operations_kpi_rollups_daily (
      bucket_start,
      environment,
      source,
      action_type,
      actor_staff_key,
      actor_staff_id,
      event_count,
      error_count,
      warning_count,
      unique_entities,
      first_event_at,
      last_event_at,
      updated_at
    )
    SELECT
      bucket_start,
      environment,
      source,
      action_type,
      actor_staff_key,
      actor_staff_id,
      event_count,
      error_count,
      warning_count,
      unique_entities,
      first_event_at,
      last_event_at,
      NOW()
    FROM daily_agg
    ON CONFLICT (bucket_start, environment, source, action_type, actor_staff_key)
    DO UPDATE SET
      actor_staff_id = EXCLUDED.actor_staff_id,
      event_count = EXCLUDED.event_count,
      error_count = EXCLUDED.error_count,
      warning_count = EXCLUDED.warning_count,
      unique_entities = EXCLUDED.unique_entities,
      first_event_at = EXCLUDED.first_event_at,
      last_event_at = EXCLUDED.last_event_at,
      updated_at = NOW()
    RETURNING 1
  )
  SELECT COUNT(*)::integer INTO v_daily_rows FROM upsert_daily;

  RETURN QUERY SELECT v_hourly_rows, v_daily_rows;
END;
$$;

-- Cursor-based refresh helper for scheduled jobs.
CREATE OR REPLACE FUNCTION refresh_operations_kpi_rollups_from_state(
  p_to TIMESTAMPTZ DEFAULT NOW()
)
RETURNS TABLE (
  from_ts TIMESTAMPTZ,
  to_ts TIMESTAMPTZ,
  hourly_rows INTEGER,
  daily_rows INTEGER
)
LANGUAGE plpgsql
AS $$
DECLARE
  v_from TIMESTAMPTZ;
  v_to TIMESTAMPTZ;
  v_hourly_rows INTEGER := 0;
  v_daily_rows INTEGER := 0;
BEGIN
  SELECT last_processed_at
    INTO v_from
  FROM operations_kpi_rollup_state
  WHERE key = 'audit_logs'
  FOR UPDATE;

  IF v_from IS NULL THEN
    v_from := '1970-01-01 00:00:00+00'::timestamptz;
  END IF;

  v_to := p_to;
  IF v_to IS NULL THEN
    v_to := NOW();
  END IF;

  IF v_to <= v_from THEN
    RETURN QUERY SELECT v_from, v_to, 0, 0;
    RETURN;
  END IF;

  SELECT r.hourly_rows, r.daily_rows
    INTO v_hourly_rows, v_daily_rows
  FROM refresh_operations_kpi_rollups(v_from, v_to) r;

  UPDATE operations_kpi_rollup_state
  SET last_processed_at = v_to,
      updated_at = NOW()
  WHERE key = 'audit_logs';

  RETURN QUERY SELECT v_from, v_to, v_hourly_rows, v_daily_rows;
END;
$$;

COMMIT;

-- ============================================================
-- 2026-03-31_create_order_shipment_links.sql
-- ============================================================
-- Link table to support multiple shipment IDs per order row while preserving
-- orders.shipment_id as the canonical primary FK for backward compatibility.
CREATE TABLE IF NOT EXISTS order_shipment_links (
  order_row_id integer NOT NULL REFERENCES orders(id) ON DELETE CASCADE,
  shipment_id bigint NOT NULL,
  is_primary boolean NOT NULL DEFAULT false,
  source text,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now(),
  PRIMARY KEY (order_row_id, shipment_id)
);

CREATE INDEX IF NOT EXISTS order_shipment_links_shipment_id_idx
  ON order_shipment_links (shipment_id);

CREATE INDEX IF NOT EXISTS order_shipment_links_order_row_id_idx
  ON order_shipment_links (order_row_id);

CREATE INDEX IF NOT EXISTS order_shipment_links_primary_idx
  ON order_shipment_links (order_row_id, is_primary);

-- Keep updated_at fresh on updates.
CREATE OR REPLACE FUNCTION set_order_shipment_links_updated_at()
RETURNS trigger AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_order_shipment_links_updated_at ON order_shipment_links;
CREATE TRIGGER trg_order_shipment_links_updated_at
BEFORE UPDATE ON order_shipment_links
FOR EACH ROW
EXECUTE FUNCTION set_order_shipment_links_updated_at();

-- Backfill canonical shipment links from orders.shipment_id.
INSERT INTO order_shipment_links (order_row_id, shipment_id, is_primary, source)
SELECT o.id, o.shipment_id, true, 'orders.shipment_id.backfill'
FROM orders o
WHERE o.shipment_id IS NOT NULL
ON CONFLICT (order_row_id, shipment_id) DO UPDATE
SET is_primary = EXCLUDED.is_primary,
    source = EXCLUDED.source,
    updated_at = NOW();

-- ============================================================
-- 2026-03-31_create_staff_schedule_overrides.sql
-- ============================================================
-- Date-specific staff schedule overrides (non-recurring).
-- Used to avoid weekly-template edits affecting future weeks unintentionally.
CREATE TABLE IF NOT EXISTS staff_schedule_overrides (
  staff_id INTEGER NOT NULL REFERENCES staff(id) ON DELETE CASCADE,
  schedule_date DATE NOT NULL,
  is_scheduled BOOLEAN NOT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  PRIMARY KEY (staff_id, schedule_date)
);

CREATE INDEX IF NOT EXISTS idx_staff_schedule_overrides_date
  ON staff_schedule_overrides(schedule_date, staff_id);

-- ============================================================
-- 2026-03-31_operations_kpi_unified_sources.sql
-- ============================================================
BEGIN;

-- Normalize AUDIT + SAL into one deduped event stream for KPI rollups.
CREATE OR REPLACE VIEW operations_events_unified_v1 AS
WITH audit_events AS (
  SELECT
    al.id::bigint AS internal_id,
    al.created_at AS event_ts,
    'AUDIT'::text AS source_table,
    COALESCE(NULLIF(al.request_id, ''), 'audit:' || al.id::text) AS dedupe_key,
    COALESCE(NULLIF(al.request_id, ''), NULLIF(al.metadata->>'request_id', '')) AS request_id,
    COALESCE(NULLIF(al.source, ''), NULLIF(al.metadata->>'source', ''), 'unknown') AS source,
    al.action AS action_type,
    al.actor_staff_id,
    al.entity_type,
    al.entity_id,
    LOWER(COALESCE(NULLIF(al.metadata->>'severity', ''), '')) AS severity,
    COALESCE(sal.station, NULLIF(al.metadata->>'station', ''), NULL)::text AS station,
    al.station_activity_log_id
  FROM audit_logs al
  LEFT JOIN station_activity_logs sal ON sal.id = al.station_activity_log_id
),
sal_events AS (
  SELECT
    sal.id::bigint AS internal_id,
    sal.created_at AS event_ts,
    'SAL'::text AS source_table,
    COALESCE(
      NULLIF(sal.metadata->>'request_id', ''),
      'sal:' || sal.id::text
    ) AS dedupe_key,
    NULLIF(sal.metadata->>'request_id', '') AS request_id,
    COALESCE(NULLIF(sal.metadata->>'source', ''), LOWER(NULLIF(sal.station, '')), 'unknown') AS source,
    sal.activity_type AS action_type,
    sal.staff_id AS actor_staff_id,
    CASE
      WHEN sal.orders_exception_id IS NOT NULL THEN 'ORDERS_EXCEPTION'
      WHEN sal.fba_shipment_item_id IS NOT NULL THEN 'FBA_SHIPMENT_ITEM'
      WHEN sal.fba_shipment_id IS NOT NULL THEN 'FBA_SHIPMENT'
      WHEN sal.shipment_id IS NOT NULL THEN 'SHIPMENT'
      WHEN sal.tech_serial_number_id IS NOT NULL THEN 'TECH_SERIAL'
      WHEN sal.packer_log_id IS NOT NULL THEN 'PACKER_LOG'
      ELSE 'STATION_ACTIVITY'
    END AS entity_type,
    COALESCE(
      sal.orders_exception_id::text,
      sal.fba_shipment_item_id::text,
      sal.fba_shipment_id::text,
      sal.shipment_id::text,
      sal.tech_serial_number_id::text,
      sal.packer_log_id::text,
      sal.id::text
    ) AS entity_id,
    LOWER(COALESCE(NULLIF(sal.metadata->>'severity', ''), '')) AS severity,
    sal.station::text AS station,
    sal.id AS station_activity_log_id
  FROM station_activity_logs sal
  WHERE NOT EXISTS (
    SELECT 1
    FROM audit_logs al
    WHERE al.station_activity_log_id = sal.id
  )
),
combined AS (
  SELECT * FROM audit_events
  UNION ALL
  SELECT * FROM sal_events
),
ranked AS (
  SELECT
    c.*,
    ROW_NUMBER() OVER (
      PARTITION BY
        COALESCE(
          NULLIF(c.request_id, ''),
          NULLIF(c.dedupe_key, ''),
          (
            COALESCE(c.actor_staff_id::text, '-1')
            || '|'
            || COALESCE(c.action_type, '')
            || '|'
            || COALESCE(c.entity_type, '')
            || '|'
            || COALESCE(c.entity_id, '')
            || '|'
            || date_trunc('minute', c.event_ts)::text
          )
        )
      ORDER BY
        CASE WHEN c.source_table = 'AUDIT' THEN 0 ELSE 1 END,
        c.event_ts DESC,
        c.internal_id DESC
    ) AS dedupe_rank
  FROM combined c
)
SELECT
  source_table || ':' || internal_id::text AS event_id,
  event_ts,
  source_table,
  source,
  action_type,
  actor_staff_id,
  entity_type,
  entity_id,
  severity,
  station,
  station_activity_log_id,
  request_id
FROM ranked
WHERE dedupe_rank = 1;

-- Add state key for unified source processing; preserve old cursor when present.
INSERT INTO operations_kpi_rollup_state (key, last_processed_at)
VALUES (
  'operations_events',
  COALESCE(
    (SELECT s.last_processed_at FROM operations_kpi_rollup_state s WHERE s.key = 'audit_logs'),
    '1970-01-01 00:00:00+00'::timestamptz
  )
)
ON CONFLICT (key) DO NOTHING;

CREATE OR REPLACE FUNCTION refresh_operations_kpi_rollups(
  p_from TIMESTAMPTZ,
  p_to TIMESTAMPTZ
)
RETURNS TABLE (hourly_rows INTEGER, daily_rows INTEGER)
LANGUAGE plpgsql
AS $$
DECLARE
  v_hourly_rows INTEGER := 0;
  v_daily_rows INTEGER := 0;
BEGIN
  IF p_from IS NULL OR p_to IS NULL THEN
    RAISE EXCEPTION 'refresh_operations_kpi_rollups requires non-null p_from and p_to';
  END IF;

  IF p_to <= p_from THEN
    RAISE EXCEPTION 'refresh_operations_kpi_rollups requires p_to > p_from (got %, %)', p_from, p_to;
  END IF;

  WITH unified AS (
    SELECT *
    FROM operations_events_unified_v1 u
    WHERE u.event_ts >= p_from
      AND u.event_ts < p_to
  ),
  hourly_agg AS (
    SELECT
      date_trunc('hour', event_ts) AS bucket_start,
      'prod'::text AS environment,
      source,
      action_type,
      COALESCE(actor_staff_id, -1) AS actor_staff_key,
      actor_staff_id,
      COUNT(*)::integer AS event_count,
      SUM(
        CASE
          WHEN severity = 'error'
            OR action_type ILIKE '%ERROR%'
            OR action_type ILIKE '%FAILED%'
            OR action_type ILIKE '%EXCEPTION%'
          THEN 1 ELSE 0
        END
      )::integer AS error_count,
      SUM(
        CASE
          WHEN severity = 'warning'
            OR action_type ILIKE '%WARN%'
            OR action_type ILIKE '%RETRY%'
            OR action_type ILIKE '%AT_RISK%'
          THEN 1 ELSE 0
        END
      )::integer AS warning_count,
      COUNT(DISTINCT (entity_type || ':' || entity_id)) FILTER (
        WHERE entity_type IS NOT NULL
          AND entity_type <> ''
          AND entity_id IS NOT NULL
          AND entity_id <> ''
      )::integer AS unique_entities,
      MIN(event_ts) AS first_event_at,
      MAX(event_ts) AS last_event_at
    FROM unified
    GROUP BY 1, 2, 3, 4, 5, 6
  ),
  upsert_hourly AS (
    INSERT INTO operations_kpi_rollups_hourly (
      bucket_start,
      environment,
      source,
      action_type,
      actor_staff_key,
      actor_staff_id,
      event_count,
      error_count,
      warning_count,
      unique_entities,
      first_event_at,
      last_event_at,
      updated_at
    )
    SELECT
      bucket_start,
      environment,
      source,
      action_type,
      actor_staff_key,
      actor_staff_id,
      event_count,
      error_count,
      warning_count,
      unique_entities,
      first_event_at,
      last_event_at,
      NOW()
    FROM hourly_agg
    ON CONFLICT (bucket_start, environment, source, action_type, actor_staff_key)
    DO UPDATE SET
      actor_staff_id = EXCLUDED.actor_staff_id,
      event_count = EXCLUDED.event_count,
      error_count = EXCLUDED.error_count,
      warning_count = EXCLUDED.warning_count,
      unique_entities = EXCLUDED.unique_entities,
      first_event_at = EXCLUDED.first_event_at,
      last_event_at = EXCLUDED.last_event_at,
      updated_at = NOW()
    RETURNING 1
  )
  SELECT COUNT(*)::integer INTO v_hourly_rows FROM upsert_hourly;

  WITH unified AS (
    SELECT *
    FROM operations_events_unified_v1 u
    WHERE u.event_ts >= p_from
      AND u.event_ts < p_to
  ),
  daily_agg AS (
    SELECT
      date_trunc('day', event_ts)::date AS bucket_start,
      'prod'::text AS environment,
      source,
      action_type,
      COALESCE(actor_staff_id, -1) AS actor_staff_key,
      actor_staff_id,
      COUNT(*)::integer AS event_count,
      SUM(
        CASE
          WHEN severity = 'error'
            OR action_type ILIKE '%ERROR%'
            OR action_type ILIKE '%FAILED%'
            OR action_type ILIKE '%EXCEPTION%'
          THEN 1 ELSE 0
        END
      )::integer AS error_count,
      SUM(
        CASE
          WHEN severity = 'warning'
            OR action_type ILIKE '%WARN%'
            OR action_type ILIKE '%RETRY%'
            OR action_type ILIKE '%AT_RISK%'
          THEN 1 ELSE 0
        END
      )::integer AS warning_count,
      COUNT(DISTINCT (entity_type || ':' || entity_id)) FILTER (
        WHERE entity_type IS NOT NULL
          AND entity_type <> ''
          AND entity_id IS NOT NULL
          AND entity_id <> ''
      )::integer AS unique_entities,
      MIN(event_ts) AS first_event_at,
      MAX(event_ts) AS last_event_at
    FROM unified
    GROUP BY 1, 2, 3, 4, 5, 6
  ),
  upsert_daily AS (
    INSERT INTO operations_kpi_rollups_daily (
      bucket_start,
      environment,
      source,
      action_type,
      actor_staff_key,
      actor_staff_id,
      event_count,
      error_count,
      warning_count,
      unique_entities,
      first_event_at,
      last_event_at,
      updated_at
    )
    SELECT
      bucket_start,
      environment,
      source,
      action_type,
      actor_staff_key,
      actor_staff_id,
      event_count,
      error_count,
      warning_count,
      unique_entities,
      first_event_at,
      last_event_at,
      NOW()
    FROM daily_agg
    ON CONFLICT (bucket_start, environment, source, action_type, actor_staff_key)
    DO UPDATE SET
      actor_staff_id = EXCLUDED.actor_staff_id,
      event_count = EXCLUDED.event_count,
      error_count = EXCLUDED.error_count,
      warning_count = EXCLUDED.warning_count,
      unique_entities = EXCLUDED.unique_entities,
      first_event_at = EXCLUDED.first_event_at,
      last_event_at = EXCLUDED.last_event_at,
      updated_at = NOW()
    RETURNING 1
  )
  SELECT COUNT(*)::integer INTO v_daily_rows FROM upsert_daily;

  RETURN QUERY SELECT v_hourly_rows, v_daily_rows;
END;
$$;

CREATE OR REPLACE FUNCTION refresh_operations_kpi_rollups_from_state(
  p_to TIMESTAMPTZ DEFAULT NOW()
)
RETURNS TABLE (
  from_ts TIMESTAMPTZ,
  to_ts TIMESTAMPTZ,
  hourly_rows INTEGER,
  daily_rows INTEGER
)
LANGUAGE plpgsql
AS $$
DECLARE
  v_from TIMESTAMPTZ;
  v_to TIMESTAMPTZ;
  v_hourly_rows INTEGER := 0;
  v_daily_rows INTEGER := 0;
BEGIN
  SELECT last_processed_at
    INTO v_from
  FROM operations_kpi_rollup_state
  WHERE key = 'operations_events'
  FOR UPDATE;

  IF v_from IS NULL THEN
    v_from := '1970-01-01 00:00:00+00'::timestamptz;
  END IF;

  v_to := COALESCE(p_to, NOW());

  IF v_to <= v_from THEN
    RETURN QUERY SELECT v_from, v_to, 0, 0;
    RETURN;
  END IF;

  SELECT r.hourly_rows, r.daily_rows
    INTO v_hourly_rows, v_daily_rows
  FROM refresh_operations_kpi_rollups(v_from, v_to) r;

  UPDATE operations_kpi_rollup_state
  SET last_processed_at = v_to,
      updated_at = NOW()
  WHERE key = 'operations_events';

  RETURN QUERY SELECT v_from, v_to, v_hourly_rows, v_daily_rows;
END;
$$;

COMMIT;

-- ============================================================
-- 2026-03-31_tsn_add_station_source_and_receiving_line.sql
-- ============================================================
-- Add receiving-context linkage to tech_serial_numbers while keeping existing TECH/FBA flows intact.
-- Lean model:
--   - station_source: where the serial event originated
--   - receiving_line_id: optional FK for receiving/unboxing serial capture

BEGIN;

ALTER TABLE tech_serial_numbers
  ADD COLUMN IF NOT EXISTS station_source TEXT NOT NULL DEFAULT 'TECH',
  ADD COLUMN IF NOT EXISTS receiving_line_id INTEGER REFERENCES receiving_lines(id) ON DELETE SET NULL;

ALTER TABLE tech_serial_numbers
  DROP CONSTRAINT IF EXISTS chk_tech_serial_numbers_station_source;

ALTER TABLE tech_serial_numbers
  ADD CONSTRAINT chk_tech_serial_numbers_station_source
  CHECK (station_source IN ('TECH', 'RECEIVING', 'PACK', 'ADMIN'));

-- Receiving rows must carry a line anchor.
ALTER TABLE tech_serial_numbers
  DROP CONSTRAINT IF EXISTS chk_tech_serial_numbers_receiving_line_required;

ALTER TABLE tech_serial_numbers
  ADD CONSTRAINT chk_tech_serial_numbers_receiving_line_required
  CHECK (station_source <> 'RECEIVING' OR receiving_line_id IS NOT NULL);

CREATE INDEX IF NOT EXISTS idx_tsn_station_source_created
  ON tech_serial_numbers(station_source, created_at DESC);

CREATE INDEX IF NOT EXISTS idx_tsn_receiving_line_id
  ON tech_serial_numbers(receiving_line_id)
  WHERE receiving_line_id IS NOT NULL;

-- De-duplicate only within the same receiving line.
CREATE UNIQUE INDEX IF NOT EXISTS ux_tsn_receiving_line_serial
  ON tech_serial_numbers(receiving_line_id, UPPER(BTRIM(serial_number)))
  WHERE receiving_line_id IS NOT NULL;

COMMIT;

